VALUES ('646fd20a-2adb-469c-b47b-907b566efce0', 'EyeBreathalyzer by HazyEyes', 'eyebreathalyzer-by-hazyeyes', 'AI impairment screening in 15 seconds', 'EyeBreathalyzer employs AI-powered eye tracking to swiftly detect signs of alcohol, drug-related impairment, and fatigue within 15 seconds. This innovative device eliminates the need for traditional breathalyzers and specialized hardware, making it a versatile solution for various applications. Its primary focus lies in enhancing public safety, workplace safety, transportation, and high-risk environments where real-time impairment assessments are crucial.', 'https://ph-files.imgix.net/4dd92d42-06cb-4686-afe7-3171d3e57560.png?auto=format', 'https://www.producthunt.com/r/WTQVX3A5WFSCUW?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/WTQVX3A5WFSCUW?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'writing', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 1, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:12.037Z', NULL, NULL, 'manual', NULL)
