VALUES ('9e2eadae-1530-4d91-a5bb-dab7b0bce100', 'BrainHey', 'brainhey', 'Master Your Mind, One Entry at a Time', 'Master your mind with BrainHey, the AI-powered mental health journal. Track your mood, analyze journal entries with CBT, and regulate anxiety. Most anxiety apps teach you to breathe through it. BrainHey teaches you why it''s happening. AI-powered journaling built on CBT, the most evidence-backed therapy for anxiety. Write how you feel, and BrainHey identifies your thought patterns, cognitive distortions, and emotional triggers. Free to start. No meditation required.', 'https://ph-files.imgix.net/ce1c571e-5a87-44c7-8c8a-19814264eaa1.png?auto=format', 'https://www.producthunt.com/r/5HUIOPTVIJMIXC?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/5HUIOPTVIJMIXC?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'writing', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:12.045Z', NULL, NULL, 'manual', NULL)
