VALUES ('cb686bf5-d011-409d-89ad-379d608472cc', 'u1social™', 'u1social', 'Reclaiming the Digital Sanctuary: Private, AI-Moderated', 'u1social™ is your Digital Sanctuary. Engineered to replace the "data-for-access" model with privacy, we offer an ad-free, AI-moderated space for your inner circle. 🛡️ Key Features: • Privacy by Design: No data-mining or intrusive ads. • AI Moderation: A clean, safe environment by default. • XP Economy: Earn tokens through contribution to unlock premium AI features for FREE. Join our Pioneers to co-create a healthier digital legacy. Safe. Private. Ours. 🏁', 'https://ph-files.imgix.net/baee63ae-d76d-4012-a9aa-c496e8e485f5.png?auto=format', 'https://www.producthunt.com/r/YG36Q4GCLKYPLR?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/YG36Q4GCLKYPLR?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'writing', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 1, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:12.052Z', NULL, NULL, 'manual', NULL)
