VALUES ('b6e6c199-daa8-4ce4-837a-a3658011306b', 'Follow the Rabbits', 'follow-the-rabbits', 'daily summaries of new papers about your interests', 'We wanted to create an app that would allow you to stay up to date in your field or simply learn new things about topics you care about. It works by: - You describe the fields you''re interested in in plain language. - We match newly published papers to your topic. - We segment the paper into easy to skim sections and for each section we generate a deep dive if you wanna learn more and ELI5 in case you feel lost', 'https://ph-files.imgix.net/12c92e59-5295-471c-a232-856254c97263.png?auto=format', 'https://www.producthunt.com/r/ZPJPVKJ6JWZ3UR?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/ZPJPVKJ6JWZ3UR?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'writing', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:12.089Z', NULL, NULL, 'manual', NULL)
