VALUES ('74b53107-7398-4fa4-a254-16bdcff7ed5f', 'Vetract', 'vetract', 'AI contract risk analysis — know before you sign.', 'Vetract LEX analyzes any contract clause by clause and flags indemnification traps, uncapped liability, one-sided IP assignment, auto-renewal gotchas, and 120+ other risk patterns in under 60 seconds. No free trial. No fluff. Upload a PDF or DOCX and get a plain-English risk report with negotiation recommendations. Built for founders, freelancers, and legal teams who are tired of signing things they don''t fully understand. Your contracts are never stored. Zero document retention, always.', 'https://ph-files.imgix.net/096fb62f-d2c0-41c5-aefe-c85cbafde81c.png?auto=format', 'https://www.producthunt.com/r/QM4OBE6UPSPITY?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/QM4OBE6UPSPITY?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'writing', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:12.104Z', NULL, NULL, 'manual', NULL)
