VALUES ('b8290b2a-d8bc-44e1-958e-0de5e504476e', 'Snapwell', 'snapwell', 'Your inspiration library, organized by AI ', 'Collect images and videos from anywhere, Snapwell uses AI to analyze every item automatically, so you can search by what you see instead of digging through folders. Choose your own AI provider (Claude, OpenAI, Gemini). All data stays on your devices and iCloud — no accounts, no servers, no tracking. Native Mac and iOS apps with iCloud sync. Open source.', 'https://ph-files.imgix.net/21ec7405-f9db-42b8-9fec-2f77a017b297.png?auto=format', 'https://www.producthunt.com/r/IEVZGD6EBSMI6Z?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/IEVZGD6EBSMI6Z?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'design', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'free', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 3, 0, 1, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:12.120Z', NULL, NULL, 'manual', NULL)
