VALUES ('df89a6d5-1b91-4cc6-95c6-8867eb4f4ae1', 'Claude 2026: Latest Tools Guide', 'claude-2026-latest-tools-guide', 'Claude 2026 Tutorial: Latest Features Explained', 'A practical Claude workflow for creators, developers, and AI users who want more than basic chatbot outputs. This video turns one tiny pixel game idea into a complete creative workflow using model selection, web search, structured prompting, context interviews, file uploads, artifacts, projects, memory, custom instructions, skills, connectors, research mode, Claude Code, and Co-Work. The final result is a clear game concept, design document, prototype checklist, and launch package.', 'https://ph-files.imgix.net/a3a0e8c5-8bd5-4293-9f18-ed9538306ba7.png?auto=format', 'https://www.producthunt.com/r/DY45BB4W4ESTGY?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/DY45BB4W4ESTGY?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'productivity', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:12.128Z', NULL, NULL, 'manual', NULL)
