VALUES ('ff0b2b2a-9828-4f96-9e00-e7cf20d54ab2', 'CV Rank Battle', 'cv-rank-battle', 'Rank your resume against real competitors.', 'Meet CV Rank Battle Stop guessing if your resume is good enough. How it works: Upload your CV. See how you rank against real competitor resumes. Challenge your friends. Climb the leaderboard. CV Rank Battle is the AI platform where ambitious professionals compare, rank, and improve their resumes.', 'https://ph-files.imgix.net/fa455b9e-ca6d-4275-bde5-8b4052dcb424.svg?auto=format', 'https://www.producthunt.com/r/UA3CP6MG7OURAA?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/UA3CP6MG7OURAA?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'writing', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:12.137Z', NULL, NULL, 'manual', NULL)
