VALUES ('3e14553b-5ed0-4e04-b7a7-4063c1bfe59a', 'TuckMeIn', 'tuckmein', 'Create personalized bedtime stories in seconds', 'Punchy / PH-native Bedtime stories, starring your kid as the hero. 🌙 TuckMeIn uses your child''s age, interests, friends, and pets to generate a fully personalized story in seconds — with audio narration and a printable version included. Play it. Print it. Skip the screen. Try your first story free. No signup needed.', 'https://ph-files.imgix.net/06bbb9ac-c321-4ca1-beae-35260f56c4b6.png?auto=format', 'https://www.producthunt.com/r/A7AECHGFMUQLBU?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/A7AECHGFMUQLBU?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'writing', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:12.152Z', NULL, NULL, 'manual', NULL)
