VALUES ('68e22066-0db5-40c7-ae37-c51626b2d52c', 'Ignyte', 'ignyte', 'The all-in-one AI workspace for startup founders', 'Ignyte helps startup founders organize and run their business with AI-powered tools, founder resources, workflows, CRM, and productivity systems, all in one workspace. Instead of juggling dozens of tools, founders can manage execution, planning, operations, and growth from a single platform designed specifically for startups. Built for fast-moving founders who want clarity, speed, and leverage.', 'https://ph-files.imgix.net/100e00dc-b24b-405b-8de0-a8dc0cf9e88e.png?auto=format', 'https://www.producthunt.com/r/GIDPGTUN6UBMY4?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/GIDPGTUN6UBMY4?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'productivity', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 1, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:12.160Z', NULL, NULL, 'manual', NULL)
