VALUES ('636635d3-ead7-4759-b5f3-6427ce226e9a', 'Micropedia AI Search Optimizer', 'micropedia-ai-search-optimizer', 'Prepare WordPress for AI Search and intelligent agents', 'Micropedia AI Search Optimizer helps make WordPress websites more readable for AI systems through llms.txt, Markdown export, semantic enhancements and AI crawler controls.', 'https://ph-files.imgix.net/fd18efd2-711b-467d-a6b7-832099577a55.png?auto=format', 'https://www.producthunt.com/r/Q5TNAQ633TRNSL?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/Q5TNAQ633TRNSL?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'marketing', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:12.167Z', NULL, NULL, 'manual', NULL)
