VALUES ('4aae6857-b2f2-44b0-8610-6ac8113c038e', 'Boy and a Scanner', 'boy-and-a-scanner', 'AI-powered scanner frequency assistant for hobbyists', 'Boy and a Scanner is the world''s first AI-powered scanner frequency assistant for public safety hobbyists, preppers, and ham radio fans. Paste any ZIP or city to get instant police/fire/EMS frequencies with one-tap programming guides for your scanner. AI cross-references RadioReference so you never program dead channels. Route Recon Trip Planner maps frequencies along your entire route. 1,377+ community-indexed locations.', 'https://ph-files.imgix.net/0a8ca79a-7807-4f90-85da-8d148329d162.jpeg?auto=format', 'https://www.producthunt.com/r/POB7DEEOQNSSIW?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/POB7DEEOQNSSIW?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'productivity', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 1, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:12.176Z', NULL, NULL, 'manual', NULL)
