VALUES ('3264a2d6-9a3f-4ed6-8397-9849776c9ed4', 'MissPotts_Computer', 'misspotts-computer', 'AI assistant computer that lives wherever you want', 'Hi everyone, we are releasing MissPotts Computer (https://misspotts.ai/computer) to the world today. We know that it is not perfect but we are constantly working on improving it. We are eager to learn about how we can give a better version of this technology to you. So please reach out to us and we will listen.', 'https://ph-files.imgix.net/a5d0befb-784c-417a-a5d4-839d883cea0f.svg?auto=format', 'https://www.producthunt.com/r/6ZH2SWFIRS76LG?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/6ZH2SWFIRS76LG?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'writing', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:12.183Z', NULL, NULL, 'manual', NULL)
