VALUES ('40a3a282-9955-4037-a489-77fb3a0f677f', 'Sortlist', 'sortlist', 'Save any product. AI sorts it instantly', '🙋 You: 40 tabs open, three wishlists, a dozen screenshots, zero idea what you actually wanted to buy. 🛍️ Sortlist: one click to save, AI sorts it for you. How it works: 1. Install the Chrome extension (or paste a URL) 2. Hit save on any product, anywhere 3. AI drops it into the right smart folder automatically 4. Come back when you''re ready to buy Free. No ads. iOS/Android apps in development. 💬 Feedback, bug reports, feature ideas — all welcome. Reading every comment today.', 'https://ph-files.imgix.net/520ecfe6-aac6-4836-b07c-968a11cf241a.svg?auto=format', 'https://www.producthunt.com/r/ZQ25K2Z2JSYBLX?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/ZQ25K2Z2JSYBLX?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'productivity', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 1, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:12.189Z', NULL, NULL, 'manual', NULL)
