VALUES ('e8fd81c3-b71a-40f4-8027-fe11b85b64ec', 'The Active Learning Ecosystem', 'the-active-learning-ecosystem', 'Transform static lessons into interactive experiences', 'BHLEARN is a versatile educational ecosystem built to transform how knowledge is shared and consumed. Founded on the principle of "Share | Interact | Create," the platform moves beyond traditional static learning to provide a dynamic, engaging environment for all users.', 'https://ph-files.imgix.net/3ea8e4b2-fe71-4487-bff0-f013b66fe402.png?auto=format', 'https://www.producthunt.com/r/DWAXDYWC3ETIXW?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/DWAXDYWC3ETIXW?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'productivity', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:12.196Z', NULL, NULL, 'manual', NULL)
