VALUES ('32d1c3f4-7b3b-475b-929b-e9350a3458e8', 'Via', 'via', 'AI-powered daily quests to become your future self', 'Via gives you 3 AI-powered daily quests every morning based on your life goals — whether that''s moving abroad, getting fit, launching a project, or learning new skills. Complete quests → earn XP → level up → watch your city grow on an animated map. 🎯 30+ life goals across 7 categories ⚔️ AI generates personalized quests daily 🗺️ Living city map that evolves with your level 🏆 Achievements, streaks, and stats 📱 Works on mobile and desktop', 'https://ph-files.imgix.net/737b3b11-e734-4018-b670-69ff58736a88.png?auto=format', 'https://www.producthunt.com/r/IULDN6SM6AMUUP?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/IULDN6SM6AMUUP?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'productivity', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:12.211Z', NULL, NULL, 'manual', NULL)
