VALUES ('0a622835-d346-4525-a2d6-b3e5d6c70585', 'SkillPrompts', 'skillprompts', 'Less typing. More thinking. Better AI results.', 'Ever find yourself rewriting the same AI prompts over and over again? SkillPrompts is a simple browser extension that lets you save, organize, and reuse your prompts in one place. You can quickly insert them into ChatGPT and other AI tools, customize them with variables when needed, and use ready-made prompts to speed up your work and make your AI interactions more efficient.', 'https://ph-files.imgix.net/34d6579b-cbc0-4652-a5ae-560b60cb5f3f.png?auto=format', 'https://www.producthunt.com/r/747XZS37CDEIGD?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/747XZS37CDEIGD?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'writing', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 2, 0, 1, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:12.226Z', NULL, NULL, 'manual', NULL)
