VALUES ('9a4352c7-40b3-4cca-a657-2ca9f72d3eaf', 'Zenosfy', 'zenosfy', '    Turn your business into an AI-powered company', 'Zenosfy makes AI employees accessible to any business owner, even with no technical experience. Instead of dealing with prompts, workflows, and complex integrations, users simply describe their business and goals, and Zenosfy generates customized AI agents in minutes. Create AI receptionists, lead capture agents, appointment setters, and support assistants—all in one platform. It turns advanced AI automation into a simple, outcome-driven experience focused on saving time and increasing revenue.', 'https://ph-files.imgix.net/1f27335f-1dff-469a-8412-d980cd3010de.png?auto=format', 'https://www.producthunt.com/r/LHZ5DBVHB3EUDN?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/LHZ5DBVHB3EUDN?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'writing', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:12.234Z', NULL, NULL, 'manual', NULL)
