VALUES ('f4937b3f-db0c-43b3-a7f6-d1909b37d0f7', 'Prospect Insights', 'prospect-insights', 'Research any prospect in 30 seconds', 'Prospect Insights helps salespeople research any company in 30 seconds instead of hours on LinkedIn. Get instant intelligence: revenue, employee count, decision makers with titles, funding status, industry, and growth signals. Upload a CSV of 100 prospects and research them all at once. Export results and use them in your CRM or sales engagement tool. Perfect for SDRs, account executives, and sales leaders who want to move faster.', 'https://ph-files.imgix.net/97ab9bf8-9962-4077-8872-81792555100a.jpeg?auto=format', 'https://www.producthunt.com/r/ULWCC6Z7E4XIHY?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/ULWCC6Z7E4XIHY?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'productivity', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:12.240Z', NULL, NULL, 'manual', NULL)
