VALUES ('e53a8518-f086-48d6-836e-4843a136cbb4', 'VisaiPath', 'visaipath', 'EB-1 & EB-2 visa document drafting system', 'VisaiPath is an EB-1 and EB-2 full petition preparation platform: petition letter, cover letter, achievement summary, resume, evidence index, Form I-140 and ETA-9089 workflows, and organized filing-ready exports—plus eligibility assessment. Not a recommendation-letter-only tool; it structures your entire self-petition package.', 'https://ph-files.imgix.net/4885bebd-048c-444f-bb0f-7da6b4d7dfef.png?auto=format', 'https://www.producthunt.com/r/NFJ6QPBV3BIOK2?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/NFJ6QPBV3BIOK2?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'writing', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:12.247Z', NULL, NULL, 'manual', NULL)
