VALUES ('932a5c79-13fa-44c2-8ef1-5cf82978dcfa', 'DNTR Kampüs', 'dntr-kamp-s', 'Connect, discover, and grow on campus.', 'DNTR Kampüs is a student-focused digital campus platform that brings university life into one app. Students can follow campus events and announcements, connect with communities, discover job and internship opportunities through partner brands, and earn Thank Points through engagement. It creates a more connected, rewarding, and accessible campus experience for students, clubs, and universities.', 'https://ph-files.imgix.net/2beb2a8f-fb87-4d09-a6cd-dd48e88a3255.png?auto=format', 'https://www.producthunt.com/r/NMWJTQFZGHWKLU?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/NMWJTQFZGHWKLU?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'productivity', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:12.254Z', NULL, NULL, 'manual', NULL)
