VALUES ('8a3c6e3b-566b-4453-9f9f-0b2dc772a4fa', 'Sensei', 'sensei', 'You built the product... Now what?', 'Sensei reads your site, your rivals, your real metrics (when you wire Stripe) — and gives you ONE verdict and ONE move every Monday. Built for vibe coders and solo founders, not VC-backed teams. What stands out: • Editorial design — not a dashboard with 47 vanity tiles • Grounded in real Lighthouse + competitive data, not LLM guesses • A weekly rhythm, not on-demand chat — Sensei reads THIS week, every week', 'https://ph-files.imgix.net/00a1b990-fdec-46e6-9efa-b8813d3e8de1.png?auto=format', 'https://www.producthunt.com/r/PUZKCSGSQC7THU?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/PUZKCSGSQC7THU?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'marketing', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:12.268Z', NULL, NULL, 'manual', NULL)
