VALUES ('b943aa66-a41d-4a03-bcba-28c116983d96', 'tautest', 'tautest', 'Mutation testing workflow for AI-written tests', 'Tautest is different because it combines mutation testing with an AI-agent workflow. It uses StrykerJS as the engine, then adds changed-line PR scoping, surviving mutant reports, AI-ready fix prompts, and GitHub sticky comments. Instead of only asking whether tests pass, it asks whether tests fail when the changed code is mutated. It is built for teams using Claude Code, Cursor, Codex, or Copilot who want stronger test feedback without calling any LLM API itself. CLI and CI ready. Open source!!!', 'https://ph-files.imgix.net/0580e5f9-f98c-4fa5-8386-9167cb99bd40.png?auto=format', 'https://www.producthunt.com/r/3G36QOJEZ3LPJB?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/3G36QOJEZ3LPJB?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'writing', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'free', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:12.284Z', NULL, NULL, 'manual', NULL)
