VALUES ('50920af1-9af1-4161-929e-025643407341', 'Prompt Power', 'prompt-power', 'Turn rough ideas into cinematic AI prompts — BYOK', 'Most AI images fall flat because the prompt lacks structure — not the model. Prompt Power acts as your Senior Cinematographer, auto-assigning lens specs, f-stops, and cinematic motion based on your subject. V1.1.0: Dynamic Reasoning, Right-Click Improve, Style Quick-Chips (Cinematic/Realistic/Anime/Digital Art), Obsidian Dark Mode, PRO Cleanup. BYOK — no accounts, no tracking. Free and Pro versions.', 'https://ph-files.imgix.net/974e78da-ac86-4b95-be09-403bf17f05cb.png?auto=format', 'https://www.producthunt.com/r/ML2LDUFPTIDYQP?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/ML2LDUFPTIDYQP?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'design', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:29.219Z', NULL, NULL, 'manual', NULL)
