VALUES ('aa1ab45e-e3c6-4fd2-9d31-d625549d6d66', 'Media Mash', 'media-mash', 'Lightning-fast, private media tools that run in your browser', 'Media Mash is a fast, lightweight, and completely private suite of media processing tools that works entirely in your browser. Key Features: Instant image compression (JPG, PNG, WebP) Video format conversion & trimming Audio conversion & editing Batch processing support Clean, modern interface Works offline after initial load Zero data collection', 'https://ph-files.imgix.net/afe215b0-fe3c-4890-a8f1-6b8aaacc7857.png?auto=format', 'https://www.producthunt.com/r/FYJKY47P43RCXE?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/FYJKY47P43RCXE?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'design', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:29.227Z', NULL, NULL, 'manual', NULL)
