VALUES ('3a124c14-3981-48dc-aef3-e52d713fa656', 'openblog', 'openblog', 'Open-source blog platform powered by Flask & TiDB', 'OpenBlog is an open-source blogging platform built with Flask and TiDB. Deploy free on Hugging Face Spaces with one click — no complex setup needed. Features: Markdown editor with live preview, OAuth login, multi-language support, article scheduling, tags, categories, bookmarks, likes, admin dashboard with user management. Unlike WordPress or Ghost, OpenBlog is lightweight and can be deployed at zero cost. Start writing in minutes.', 'https://ph-files.imgix.net/82dcc5c0-8d16-43be-b482-b84e232891d4.png?auto=format', 'https://www.producthunt.com/r/JL2UDITVQ5PTTS?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/JL2UDITVQ5PTTS?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'productivity', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'free', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:29.236Z', NULL, NULL, 'manual', NULL)
