VALUES ('6efbec04-758f-4106-b57d-3e8a9b65a971', 'staffSign', 'staffsign', 'Employment contracts via AI agents — MCP server for HR.', 'staffSign is the first MCP server for digital employment contracts in the DACH region. Connect your AI agent (Claude, Cursor, or any MCP-compatible client) and create, send, and track employment contracts without leaving your workflow. 12 tools including template management, e-signature dispatch, and status tracking. Built for HR teams, staffing agencies, and logistics companies handling high contract volumes. Supports AES and QES/eIDAS qualified e-signatures — EU-compliant, GDPR-ready.', 'https://ph-files.imgix.net/f5348726-6387-4ef2-a9f9-ce198e4368a4.png?auto=format', 'https://www.producthunt.com/r/CSJDTBTVJ5WELQ?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/CSJDTBTVJ5WELQ?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'productivity', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:29.400Z', NULL, NULL, 'manual', NULL)
