VALUES ('041b4995-1f4f-4ad7-97b0-e8bdb411d35f', 'WeLinkly', 'welinkly', 'Bundle multiple links into one URL.', 'WeLinkly is a platform designed to simplify the way people organize and share links online. Instead of sending multiple URLs separately across chats, emails, or documents, WeLinkly allows users to combine everything into a single clean and shareable bundle. The WeLinkly Chrome Extension makes the process even faster by allowing users to create bundles directly while browsing. Everything automatically syncs with the user’s WeLinkly account, making everything accessible through the history page.', 'https://ph-files.imgix.net/5b6c13ea-a02d-4fa7-ac61-2cc732504e33.png?auto=format', 'https://www.producthunt.com/r/YE5X5DILRYOXRP?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/YE5X5DILRYOXRP?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'code', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:29.407Z', NULL, NULL, 'manual', NULL)
