VALUES ('cc80148e-a40d-4eb6-ba7a-dd8f7c9d84f7', 'SideCli', 'sidecli', 'Auto-hide Sidebar Terminal for macOS', 'SideCli is a lightweight native terminal for macOS built to stay out of your way. 100% free to use. Its main feature is edge-snapping: move your mouse to the screen edge and the terminal instantly slides out; move away and it hides again. No hotkeys, no window juggling, no clutter. Supports multi-monitor setups, pin mode, tabs, split panes, dark/light themes, and more — all in a ~3MB open-source app built with xterm.js.', 'https://ph-files.imgix.net/dbc2cc47-49c6-4b0a-8ef3-ca53b37f6fde.png?auto=format', 'https://www.producthunt.com/r/OUFXOOYPZ3W2JY?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/OUFXOOYPZ3W2JY?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'code', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'free', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:29.436Z', NULL, NULL, 'manual', NULL)
