VALUES ('077914a5-759d-463c-8878-df4db6b462b7', 'Huexly', 'huexly', 'Pick. Check. Export. From the menu bar.', 'Huexly is a menu-bar color picker for macOS and Windows. 60 Hz loupe with 3x-58x zoom, WCAG 2.2 and APCA contrast checking, CVD simulation for three deficiency types, and export to 12 formats including CSS variables, Tailwind, and ASE. Perpetual license.', 'https://ph-files.imgix.net/640c8163-b82b-4511-a88c-6c65c7dab333.png?auto=format', 'https://www.producthunt.com/r/ZMOWCPIATNH62V?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/ZMOWCPIATNH62V?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'code', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:29.445Z', NULL, NULL, 'manual', NULL)
