VALUES ('5b0e133a-b17b-4f0d-8a6a-0a4a100a8f67', 'Web Speed', 'web-speed', 'Kill the ''Token Tax.'' 90% cheaper agents.', 'Web Speed is the logic layer for web agents. Translate any website into high-fidelity, token-efficient machine maps for AI agents. Web Speed can save agents 70%-90% on token costs when navigating the web while running faster and more reliably because of its deterministic mapping engine.', 'https://ph-files.imgix.net/501aaa71-30b9-4bd9-933a-91326bd5dcfe.jpeg?auto=format', 'https://www.producthunt.com/r/EORFJWPOR7CX6S?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/EORFJWPOR7CX6S?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'productivity', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 9, FALSE, FALSE, TRUE, FALSE, 'active', 98, 9, 49, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:29.464Z', NULL, NULL, 'manual', NULL)
