VALUES ('a5dbe02f-b5d2-4951-869c-88b2c47a0b5d', 'Warp Open-Source', 'warp-open-source', 'Agentic development environment built with the community', 'The best, longest-lasting software is built with the people who use it, so we''ve opened up Warp to the community. To make this possible, Oz-managed agents do the heavy lifting (coding, planning, testing), letting community members focus on ideas, direction, and verification. 25K+ stars added and 500+ contributors in week one.', 'https://ph-files.imgix.net/d3217cf2-1f51-4772-aa0d-497d8737ad9a.png?auto=format', 'https://www.producthunt.com/r/RXPBBH5AYSU33A?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/RXPBBH5AYSU33A?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'code', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '7.00', 17, FALSE, FALSE, TRUE, FALSE, 'active', 176, 17, 88, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:29.471Z', NULL, NULL, 'manual', NULL)
