VALUES ('fed4fd40-c946-45ae-abfa-0a228e0024d4', 'NodeClip', 'nodeclip', 'Node-based video editing for busy pros. Like n8n, for video.', 'NodeClip replaces the chaotic timeline with a node graph. Connect clips like nodes, build reusable templates with named slots (hook/intro/outro), and run the same graph across dozens of source files in one batch. Schedule renders with cron jobs, composite streams with split-screen nodes, duplicate node chains in one click. No AI, no magic: just deterministic logic. Ships as a Blender VSE plugin and a self-hosted Docker container. Now in beta — early access via waitlist.', 'https://ph-files.imgix.net/ca01e6a7-5d1b-4fab-b0ed-12e577259ff4.gif?auto=format', 'https://www.producthunt.com/r/RCVUV3LGO5O4UK?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/RCVUV3LGO5O4UK?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'productivity', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:29.485Z', NULL, NULL, 'manual', NULL)
