VALUES ('68720569-f230-4e51-bf1f-cc8d4bb67727', 'drawlineo', 'drawlineo', 'Create diagrams that don’t look boring', 'Hey Product Hunt 👋 Excited to relaunch Drawlineo today. This update is focused on simplifying and polishing the overall experience. Drawlineo is now completely free to use — just sign in with Google to unlock pro features instantly. The relaunch also includes: ✍️ new handwritten fonts ✨ more polished shapes ⚡ smoother interactions 🎨 a cleaner visual experience overall The goal behind Drawlineo has always been simple: create diagrams that don’t look boring 🙂', 'https://ph-files.imgix.net/511121aa-1d1c-46b7-9fce-12eff74d9f0d.png?auto=format', 'https://www.producthunt.com/r/JGLKMMZY7A23TW?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/JGLKMMZY7A23TW?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'design', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:29.492Z', NULL, NULL, 'manual', NULL)
