VALUES ('e94650ac-ee4b-4d7e-b7ce-8aed9969ea46', 'todos-manager', 'todos-manager', 'Simple TODO system that works directly inside IDEs', 'Todos Manager is a lightweight TODO management extension for IDEs like Cursor, Windsurf, Antigravity, VSCodium, and other Open VSX supported editors. Instead of managing tasks in separate apps or scattered comments, developers can organize everything directly inside the IDE. The extension is also designed to be AI-agent friendly, allowing AI coding agents to read, update, and mark tasks as done while working on a codebase.', 'https://ph-files.imgix.net/34003a80-95ff-4335-b0e3-d57f485f9c0b.png?auto=format', 'https://www.producthunt.com/r/3GQBQJMPCOICW3?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/3GQBQJMPCOICW3?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'productivity', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:29.499Z', NULL, NULL, 'manual', NULL)
