VALUES ('e3f4afc4-5273-48a0-a329-766f1ed5cf4e', 'Graphbit PRFlow', 'graphbit-prflow', 'AI code reviewer that catches what others miss', 'Your AI teammate that reviews every pull request before it ships. Tested on 10 real projects, PRFlow found 7 critical security issues where competitors found zero. Learns your team''s standards over time. Pay per review, not per seat.', 'https://ph-files.imgix.net/3b472422-3bb2-4185-be18-2ec7d57d6ffc.png?auto=format', 'https://www.producthunt.com/r/K4W36ZSYF7WPLV?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/K4W36ZSYF7WPLV?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'productivity', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '7.50', 28, FALSE, FALSE, TRUE, FALSE, 'active', 284, 28, 142, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:29.506Z', NULL, NULL, 'manual', NULL)
