VALUES ('74535713-e947-4dd3-b6a9-80b691910d82', 'Notchd', 'notchd', 'Zero-dependency webhook buffer with retry, DLQ, and SQLite', 'notchd sits between webhook providers (Stripe, GitHub, Slack) and your app. It receives webhooks instantly, persists them to an embedded SQLite database, and delivers them to your app with automatic retry, dead-letter queue, and event replay — all in a single binary with no external dependencies. No Redis. No PostgreSQL. No message queue. One binary, one config file.', 'https://ph-files.imgix.net/a06cabc2-b7e0-4811-908f-ea18aead31db.svg?auto=format', 'https://www.producthunt.com/r/GKVG3G2DNVXNQY?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/GKVG3G2DNVXNQY?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'code', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:29.513Z', NULL, NULL, 'manual', NULL)
