VALUES ('89bd2020-3e27-4ec2-af7a-5280b7ec31e6', 'PerfLens', 'perflens', 'Web performance audits beyond Lighthouse', 'PerfLens goes beyond a one-time Lighthouse score by keeping performance feedback inside the browser while you build and test. It gives developers live Core Web Vitals, resource diagnostics, root cause summaries, per-URL history, AI-ready fix prompts, and launch evidence packs with desktop/mobile audits, screenshots, videos, and JSON reports. The goal is simple: help developers move faster from “this is slow” to “here’s what to fix next.”', 'https://ph-files.imgix.net/47e9023e-2fef-4225-9104-32e3a8ed7edb.vnd.microsoft.icon?auto=format', 'https://www.producthunt.com/r/A2FK25PI6YTT5F?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/A2FK25PI6YTT5F?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'marketing', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 1, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:29.521Z', NULL, NULL, 'manual', NULL)
