VALUES ('a7bb3c79-4969-4ee2-9bde-11587c6346c3', 'RPCForge', 'rpcforge', 'Multi-chain Ethereum RPC you own and control', 'RPCForge is an open-source, self-hostable RPC gateway that routes requests across Ethereum, Polygon, BSC, Arbitrum & more — with built-in caching, failover, rate limiting, and a real-time dashboard. Tired of Alchemy''s free tier limits? Host your own or use our managed version. Get an API key in 30 seconds, plug it into your dApp, and see live logs & usage stats instantly. Built by a solo dev. 100% open source.', 'https://ph-files.imgix.net/4e10956d-4bfc-46a0-9edd-0f7c6bea5cec.svg?auto=format', 'https://www.producthunt.com/r/NFBT3LVKIOWEUZ?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/NFBT3LVKIOWEUZ?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'code', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'free', ARRAY[]::text[], TRUE, TRUE, '6.50', 6, FALSE, FALSE, TRUE, FALSE, 'active', 63, 6, 31, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:29.527Z', NULL, NULL, 'manual', NULL)
