VALUES ('b1c8510d-6094-413c-b145-431cf1a0bb15', 'CacheTray', 'cachetray', 'Capture anything & send it to Claude or ChatGPT in one click', 'CacheTray lives in your browser and auto-captures everything you copy — code,links, images, and text — the moment you hit Ctrl+C. Send items directly into Claude, ChatGPT, or any NotebookLM in one click. Bulk share via AirDrop, WhatsApp, or Telegram. Smart categorization, fast search (#code, #link, #image), named workspaces, and image capture with preview. Pause anytime for privacy. 100% local — no account, no tracking.', 'https://ph-files.imgix.net/00ce7677-7fd5-45e8-84ab-6ae31371d24b.png?auto=format', 'https://www.producthunt.com/r/NWAGX2JU7WPHRL?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/NWAGX2JU7WPHRL?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'productivity', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 6, FALSE, FALSE, TRUE, FALSE, 'active', 63, 6, 31, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:29.535Z', NULL, NULL, 'manual', NULL)
