VALUES ('565ecadc-2fe1-418a-9c5c-9f256d84f5bb', 'KintoPDF', 'kintopdf', 'One-click PDF invoices for kintone. 3 layouts. Zero fuss.', 'Creating invoices in kintone takes 30 minutes. Copy to Word, format, add logo, save as PDF, upload back. KintoPDF does this in 1 click. SETUP (5 minutes) Install plugin → Choose layout → Upload logo → Auto-detect fields FEATURES - 3 layouts (Modern, Classic, Minimal) - Auto-detect all fields - Company info auto-save - Logo optimization - Unlimited PDFs - Bilingual UI FOR Tech companies, law firms, consultancies, freelancers. Save 5-10 hours/month. 30-day free trial.', 'https://ph-files.imgix.net/52be8452-ebbb-4da1-9062-e3668952bd53.png?auto=format', 'https://www.producthunt.com/r/NLQ4UDXTNGR3K3?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/NLQ4UDXTNGR3K3?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'productivity', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 2, 0, 1, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:29.542Z', NULL, NULL, 'manual', NULL)
