VALUES ('b74ac9fe-d6c0-4acb-92bc-4580bc822f54', 'EnvCipher', 'envcipher', 'Local-first, AES-256 encrypted environment variable vault.', 'A lightweight desktop vault for developers. Securely manage, isolate, and export your API keys and bot tokens with military-grade AES-256 encryption. Strictly offline, no cloud sync, completely free. Built for Windows.', 'https://ph-files.imgix.net/6d720aad-257e-4aa5-9ad5-55c0810a4d7c.svg?auto=format', 'https://www.producthunt.com/r/N2MCCWKX6VIB2Z?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/N2MCCWKX6VIB2Z?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'code', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:29.555Z', NULL, NULL, 'manual', NULL)
