VALUES ('ed0402fe-098f-41c0-a3cb-8d6d2d290cf8', 'OneTempMail', 'onetempmail', 'Free Temporary Email Address', 'OneTempMail is a privacy-first, ultra-fast temporary email engine. Protect your identity and avoid spam with instant verification codes at https://onetempmail.com/. Our platform features a clean UI, no-log policy, and automated data purging for total security. Whether you''re a developer testing workflows or a user bypassing forced sign-ups, get your disposable inbox now at onetempmail.com. Fast, secure, and reliable—the last temp mail tool you’ll ever need.', 'https://ph-files.imgix.net/cc372c74-7424-4dc4-b908-c7afcf4577a9.svg?auto=format', 'https://www.producthunt.com/r/HW3JBM65SFJJI5?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/HW3JBM65SFJJI5?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'productivity', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:29.569Z', NULL, NULL, 'manual', NULL)
