VALUES ('70de9285-8a60-4879-b494-3573960d6e36', 'DartCloudFunctions', 'dartcloudfunctions', 'Run Dart functions across any cloud', 'DartCloudFunctions is a multi-cloud serverless platform built for Dart developers. Deploy and run Dart functions across cloud providers without rewriting your backend for each vendor. We built it to give Flutter and Dart teams a simpler backend workflow with portable infrastructure, scalable execution, and less cloud lock-in. Supports modern cloud-native deployment workflows with a Dart-first developer experience.', 'https://ph-files.imgix.net/3ef89e16-965d-4802-9e38-f189de7e6af6.png?auto=format', 'https://www.producthunt.com/r/RX2DYDQMZY4TRL?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/RX2DYDQMZY4TRL?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'code', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:29.577Z', NULL, NULL, 'manual', NULL)
