VALUES ('eea21b04-6e7c-4a93-8ca0-f9dc9663d319', 'Ghost-Validator', 'ghost-validator', 'AI content risk scorer – validate before you publish', 'Ghost-Validator is a REST API that scores AI-generated content before it gets published. It returns a risk score (0-100), a VALID/WARNING/DANGER verdict, specific issues detected (thin content, weak E-E-A-T, generic AI style), and actionable fixes. Built for programmatic SEO pipelines running at scale. Supports EN, FR, ES, PT, AR, HI, ZH. Free tier available.', 'https://ph-files.imgix.net/721263ac-1948-4665-a218-d1bf03933544.png?auto=format', 'https://www.producthunt.com/r/WKTPTBYU7ODKTM?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/WKTPTBYU7ODKTM?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'marketing', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:29.592Z', NULL, NULL, 'manual', NULL)
