VALUES ('048755e9-af3b-43ab-83ff-5727841f892b', 'Just Opinion', 'just-opinion', 'Embeddable comments for blogs, docs, and static websites', '- Simple embed: Add comments to your site with two lines of code. - Built for lightweight websites: A good fit for blogs, documentation, static sites, and small projects. - Page-based threads: comment threads for each pages. - Private moderation: Manage comments through your private moderation link. - Free to start: Then upgradable to Pro for higher comment limits. - Setup time: about 2 minutes - Works with: Static HTML, Hugo, Jekyll, Astro, and any framework that supports custom scripts.', 'https://ph-files.imgix.net/9654ecc0-15ed-4030-bc2b-9b7d1ba77f7a.png?auto=format', 'https://www.producthunt.com/r/PN5H44QAXYQXT6?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/PN5H44QAXYQXT6?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'code', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:29.602Z', NULL, NULL, 'manual', NULL)
