VALUES ('dce006fc-e7a8-4aed-b2ab-4ae78e6b6d9d', 'Code Bench', 'code-bench', 'Code with AI on your terms. Local-first, BYO model', 'You''re already paying Anthropic or OpenAI. Then paying your editor a subscription to call that same key on your behalf. Code Bench removes the middleman. It''s a native Mac app — open source, MIT licensed — that opens your local repo, runs an agent loop on your machine, and talks directly to whichever model you already pay for. Anthropic, OpenAI, Gemini, a local Ollama, or any OpenAI-compatible endpoint. Your keys go straight into the macOS keychain. There is no Code Bench server.', 'https://ph-files.imgix.net/e3360200-7da7-4f54-9446-9c4bd320baf8.png?auto=format', 'https://www.producthunt.com/r/ZALGCSDEF2HIZY?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/ZALGCSDEF2HIZY?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'code', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'free', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 1, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:29.609Z', NULL, NULL, 'manual', NULL)
