VALUES ('99465d44-87f1-4b57-aeda-61eb7c030bb8', 'AVA', 'ava', 'Your AI-powered mental wellness companion ', 'AVA by AVINX Systems is your AI-powered mental wellness companion. Track moods, improve sleep, chat with AI, and connect with licensed therapists.', 'https://ph-files.imgix.net/fd4cf056-5f35-4418-9e4f-e453c0b825d5.vnd.microsoft.icon?auto=format', 'https://www.producthunt.com/r/XF4NN5LDBO4AKO?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/XF4NN5LDBO4AKO?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'productivity', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 1, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:32.229Z', NULL, NULL, 'manual', NULL)
