VALUES ('b79fd988-e007-4b58-9475-8aa2214c5af0', 'Little Guys', 'little-guys', 'Solo/Small teams get their own column on PH to beat Claude', 'ProductHunt shows every launch on one page. Someone who spent six months building something on their own sits next to a big company pushing a new version of something they already sell. Little Guys fixes that. It splits the page into two columns so you can see the little guys on one side and the big guys on the other. You choose which companies count as big. You can block products you never want to see. You can create your own lists. You control what your page looks like.', 'https://ph-files.imgix.net/36707167-9953-4067-ad09-6c77687ae044.png?auto=format', 'https://www.producthunt.com/r/HISG3IBDH4PEP2?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/HISG3IBDH4PEP2?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'productivity', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 1, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:32.239Z', NULL, NULL, 'manual', NULL)
