VALUES ('57856a3e-65be-4c23-8d12-39df84fd4c38', 'TabClick', 'tabclick', 'Keep 150 important links one click away', 'TabClick is a small Chrome extension for people who keep too many useful pages open because they do not want to lose them. Instead of leaving everything as active tabs, TabClick lets you save up to 150 important links in one clean list, organize them with simple color markers, pin the most important ones at the top, rename any link, and reopen saved pages in just two clicks. I built TabClick around one idea: saving links should feel as simple as opening them.', 'https://ph-files.imgix.net/34a270f8-8927-4977-a7c5-42780bc2708a.png?auto=format', 'https://www.producthunt.com/r/YXOFRMX25QCZMJ?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/YXOFRMX25QCZMJ?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'productivity', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:32.247Z', NULL, NULL, 'manual', NULL)
