VALUES ('5ab55d95-f331-4c21-9084-326474502d41', 'Savage Mushroom Fitness', 'savage-mushroom-fitness', 'Meet the AI coach that never waits for you to show up', '🔒 147 spots at $9.99/mo remaining Claim $9.99/mo Spot → ⚡ Early Bird · Total spots 500 Only The World''s First AI Avatar Trainer Half the Price. Forever. Join early for $9.99/mo — half the price, full access, forever locked in. $9.99/mo Was $19.99/mo. 50% Off Forever 50% OFF Monthly Yearly 67% OFF Early access', 'https://ph-files.imgix.net/5c798e3d-1a52-4078-a460-4ab25443de02.png?auto=format', 'https://www.producthunt.com/r/AMJ3TNKG5UCDRN?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/AMJ3TNKG5UCDRN?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'productivity', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:32.255Z', NULL, NULL, 'manual', NULL)
