VALUES ('034325d5-28c8-455c-8390-98be1d84ec93', 'Famturf ', 'famturf', 'AI-powered rabbit farm manager with courses & quizzes', 'Manage breeding, health, feed, and sales while learning. Rabbit farming is profitable — but hard to manage without proper records. Famturf helps rabbit farmers digitize their entire farm and improve their knowledge at the same time. Famturf is built for: New rabbit farmers learning the trade Existing farmers who want better organization Commercial breeders who want more profit This is more than a tracker — it’s a rabbit farming assistant and school.', 'https://ph-files.imgix.net/5f35c55e-df95-468d-93f4-5ef6dea4d217.png?auto=format', 'https://www.producthunt.com/r/PNMPKLME5NJ6FP?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/PNMPKLME5NJ6FP?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'productivity', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 1, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:32.264Z', NULL, NULL, 'manual', NULL)
