VALUES ('8990e80f-ca8d-431d-9c93-a82871e998dd', 'db', 'db', 'See what companies(Startups) actually pay for SaaS', 'SaaS pricing is opaque. Two companies sign the same contract and pay wildly different amounts — neither would ever know. Vendr solves this for enterprises at $36K+/year. Startups just sign at list price. PriceDB fixes this: submit your contract price anonymously, see what others actually paid. Like Glassdoor, but for SaaS contracts. Transparent, community-driven, built for startups.', 'https://ph-files.imgix.net/40c76e29-c16d-463d-8c65-58c3a232b179.png?auto=format', 'https://www.producthunt.com/r/PWJRFBUDHZRO7M?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/PWJRFBUDHZRO7M?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'productivity', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:32.289Z', NULL, NULL, 'manual', NULL)
