VALUES ('ac19dcaf-6ea4-46ed-9f93-8b651e978e85', 'CSVImport', 'csvimport', 'Import CSV data into any REST API. No code required.', 'CSVImport lets you load CSV data into any REST API. It supports OpenAPI specs or manual set up. Upload your file, map fields visually, and import thousands of rows with progress tracking and retry logic. Create shareable import pages for your team. Free tier included.', 'https://ph-files.imgix.net/c79101ae-adf7-4092-9409-df3b97095a06.svg?auto=format', 'https://www.producthunt.com/r/C76EXTO5VUGTX2?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/C76EXTO5VUGTX2?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'productivity', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 1, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:32.304Z', NULL, NULL, 'manual', NULL)
