VALUES ('5eafcd04-9258-4a26-a98b-013140cb5986', 'FrontFoundry', 'frontfoundry', 'Visual workspace where every idea connects.', 'FrontFoundry is a visual workspace where you can plan, organize, and connect everything on one infinite canvas. Unlike traditional tools built around lists and tables, FrontFoundry lets you freely place cards, calendars, spreadsheets, images, docs, text, and more, then connect them visually to see relationships and workflows. Features include real-time collaboration, flexible node resizing, multiple calendar views, spreadsheet formulas, and dark mode — all in one connected workspace.', 'https://ph-files.imgix.net/dd821eac-f4e7-4463-ae82-aa23fad6f57a.png?auto=format', 'https://www.producthunt.com/r/DGHTQAFA56MTN4?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/DGHTQAFA56MTN4?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'productivity', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:32.319Z', NULL, NULL, 'manual', NULL)
