VALUES ('5eb7a086-8097-4f25-9457-bb7478dd7cf3', 'AnyPDFfiller', 'anypdffiller', 'Fill PDF forms fast: autodetect, edit, download', 'AnyPDFfiller is a browser-based PDF form filling tool built for speed and clean UX. Upload a PDF, let the app detect fillable fields automatically, complete everything through a simple side panel, and see changes live on the document preview. It supports both standard and scanned PDFs, helps users avoid awkward manual text placement, and makes filling forms much faster than traditional PDF editors. The product is focused on form completion, not bloated PDF editing.', 'https://ph-files.imgix.net/54627239-4042-45e4-9a27-57662b6689a2.x-icon?auto=format', 'https://www.producthunt.com/r/S4M7CE2QOZSKNQ?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/S4M7CE2QOZSKNQ?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'productivity', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:32.334Z', NULL, NULL, 'manual', NULL)
