VALUES ('57279fad-6116-44f6-b0d0-72bee38f7406', 'Scope', 'scope', 'scope: Lightweight CLI session manager for web hacking.', 'Stop copy-pasting Authorization tokens and cookies between tools. scope is a lightweight CLI session manager designed for security researchers. Set your base URL, headers, and proxy once, then run curl, ffuf, nuclei, sqlmap, and more with everything auto-injected. It keeps your terminal history clean, reduces manual errors, and speeds up your bug hunting workflow. Tool-agnostic, local-first, and built for speed. One session. Every tool.', 'https://ph-files.imgix.net/4c4ff5e8-5469-4676-8f2c-a418abe768da.png?auto=format', 'https://www.producthunt.com/r/BFMUCMFUEQOV44?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/BFMUCMFUEQOV44?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'productivity', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:32.443Z', NULL, NULL, 'manual', NULL)
