VALUES ('4c6f0ea2-ee3d-43fe-a961-ae5f4b6049b2', 'Alpy Studio', 'alpy-studio', 'Build end-to-end design systems for AI and enterprises', 'Alpy is a design system workspace that gives teams one canonical source of truth for building consistent UIs from foundations to production. • Set type and color once; Alpy auto-binds Foundations → Semantics • Preview components in light/dark demo, documentation, and accessibility audits • Override and validate mappings before export • Generate Design.md package for AI-ready handoffs • Export tokens, CSS, React, and Vue production-ready component code Build design systems, end-to-end. Fast.', 'https://ph-files.imgix.net/6bebdc35-c648-4d1e-817b-430216e752aa.png?auto=format', 'https://www.producthunt.com/r/USVUFB5V5FKACZ?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/USVUFB5V5FKACZ?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'design', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 3, 0, 1, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:35.030Z', NULL, NULL, 'manual', NULL)
