VALUES ('582ace91-ba69-4197-b81a-fbd707c6cd2d', 'Genpire', 'genpire', 'Make Real Products with AI, literally.', 'Most AI stops at the idea. Genpire takes it to the factory. Think Lovable, but for consumer goods manufacturing - an agentic platform that turns prompts and sketches into products, collections, and factory-ready specs, then lets you work with your own factory or tap into a vetted network for instant quotation, sampling, and bulk production. One workflow, all the way from an idea to the factory floor. Genpire makes building physical products faster, simpler, and finally accessible to anyone.', 'https://ph-files.imgix.net/1970372c-97bb-47b6-bebc-098b71c1e4cc.png?auto=format', 'https://www.producthunt.com/r/SBMCMSDZBENDWN?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/SBMCMSDZBENDWN?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'design', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '7.50', 26, FALSE, FALSE, TRUE, FALSE, 'active', 260, 26, 130, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:35.127Z', NULL, NULL, 'manual', NULL)
