VALUES ('8405aaeb-31d7-4ec6-9998-523b6c8d95f3', 'Random Album Cover Generator', 'random-album-cover-generator', 'Make album covers from emojis, gradients, and bold text.', 'A small browser tool that turns emojis, gradients, and one line of bold text into a 3000x3000 album cover you can download as JPEG or PNG. Pick two colors, choose linear or radial, drop in any emoji palette, set rotation and opacity, add a title and artist, hit Download. No login, no signup, no AI generation. It won''t replace a real designer; it''ll replace 20 minutes of fiddling with stock templates when you just need a cover for a playlist or one-off mix.', 'https://ph-files.imgix.net/bf77129b-71d7-4522-9fc0-142b43fba45d.png?auto=format', 'https://www.producthunt.com/r/USLHJKOHOEO4AZ?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/USLHJKOHOEO4AZ?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'design', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 1, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:35.142Z', NULL, NULL, 'manual', NULL)
