VALUES ('f01df448-3268-4577-8c2e-8c8f246ccaf7', 'WeTempMail', 'wetempmail', 'Simple temporary email. No registration. Just privacy.', 'WeTempMail is a temporary email service with full attachment support. PDFs, images, videos, SVG files, documents, ZIP files — all downloadable. Plus custom email addresses. No registration, no tracking, auto-delete after 24 hours. Free and private. What makes us different? Most temp mail services strip attachments. We don''t. Whether you need to receive a PDF, save an image, or download a video,or download a ZipFile— it just works. Try it now: wetempmail.com', 'https://ph-files.imgix.net/6676fb6b-f0cb-4017-9746-58125cbe1481.png?auto=format', 'https://www.producthunt.com/r/TXZPIDS6CULDOL?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/TXZPIDS6CULDOL?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'design', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:35.149Z', NULL, NULL, 'manual', NULL)
