VALUES ('98107a6d-7fc5-4158-8c99-34e45982ab61', 'ZINECORE', 'zinecore', 'create your own zines', 'Y2K & 90s zine maker. Design zines like it''s 2003. ZINECORE is your all-in-one DIY zine studio -where 90s attitude meets Y2K chaos. Create your own digital magazines using photos, text, stickers, and layered elements. Whether you''re into pop princess energy, grunge chaos, or dreamy soft-core aesthetics. This is your creative playground. No design skills needed. Just vibes.', 'https://ph-files.imgix.net/6f64dc84-0b48-4f4f-96a1-b853a0be31a4.png?auto=format', 'https://www.producthunt.com/r/IL42MBKMMK3RLM?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/IL42MBKMMK3RLM?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'design', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:35.156Z', NULL, NULL, 'manual', NULL)
