VALUES ('513f238f-a536-42a5-8ee5-e1652e3b2bc0', 'Bombop', 'bombop', 'Make Anyone a Dancer', 'Bombop is an AI dance video generator that brings still photos to life. Upload a portrait, pick a dance template, and Bombop uses motion transfer to generate a 5-15 second clip — the same moves, the same music, with your subject. Built for creators who want TikTok-ready content without animation skills, and for marketers who need scroll-stopping short-form video at scale. The template community lets you remix what others have made and share back.', 'https://ph-files.imgix.net/164f6fea-2ea9-4026-aa04-63507891cafe.x-icon?auto=format', 'https://www.producthunt.com/r/EIR7QHD6VMY2XT?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/EIR7QHD6VMY2XT?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'design', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:35.194Z', NULL, NULL, 'manual', NULL)
