VALUES ('f049228a-bfd1-4084-b575-925446fa835b', 'Dockling', 'dockling', 'Turn your pet photo into a pixel pet that lives in your dock', 'Upload a photo of your pet, partner, or anyone. Dockling turns it into a pixel pet that lives in your Mac dock, menu bar, or notch. It walks across your screen, naps when you''re idle, and reacts when you click. Built-in Pomodoro with focus streaks, quick note taker, and a daily heatmap so it doubles as a tiny productivity sidekick. 25+ pre-made packs (cats, dogs, pandas, frogs, axolotls) or generate your own. $2.99 once. No subscription, no account, all local.', 'https://ph-files.imgix.net/6b4cbc4a-c486-4ebc-b077-fba7d97ecee9.png?auto=format', 'https://www.producthunt.com/r/KQJWJJPW436ICI?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/KQJWJJPW436ICI?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'design', ARRAY['new','product-hunt']::text[], 'paid', ARRAY[]::text[], FALSE, FALSE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 3, 0, 1, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:35.209Z', NULL, NULL, 'manual', NULL)
