VALUES ('cb26df4a-856e-42a9-997d-d7beaca42b0a', 'MakeMyStickers (now with text)', 'makemystickers-now-with-text', 'Sticker sheets with images or text. Free, no signup.', 'Actually free sticker sheet maker — no signup, no watermark, no email, no trial. Upload images or type custom text, pick an Avery layout (1×1", 2" round, 56-up, hex, more), hit print. Now with text support, so you can knock out name labels, address stickers, planner quotes, or meal-prep dates without designing in Canva first. Everything runs in your browser, your images never get uploaded.', 'https://ph-files.imgix.net/4cb8bebc-7a25-477a-91cc-e03496f55361.jpeg?auto=format', 'https://www.producthunt.com/r/3X77GJG6K6QXNE?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/3X77GJG6K6QXNE?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'design', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:35.299Z', NULL, NULL, 'manual', NULL)
