VALUES ('1603c5a3-4b0b-4c53-a87e-22fe742021e2', 'Smart Choice', 'smart-choice', 'Weighted scoring for smarter, objective decisions', 'A lightweight Vue-based tool for rational decision-making. Instead of guessing, you can Add Candidates: List any products or options you''re choosing between. Define Criteria: Set the features that matter to you (Price, Specs, Design). Weighted Scoring: Assign importance to each criterion and score your options. Visual Results: See exactly which choice wins based on your own logic. No ads, no complex setup. Just a simple H5 tool to help you pick the best.', 'https://ph-files.imgix.net/f96a6b0c-8e21-4f91-ac2e-a32474034a44.png?auto=format', 'https://www.producthunt.com/r/72RRREBJ43LDQM?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/72RRREBJ43LDQM?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'design', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:35.305Z', NULL, NULL, 'manual', NULL)
