VALUES ('9469ee87-7757-4bac-9db3-bad04ce7fb44', 'CraftYourDeck', 'craftyourdeck', 'AI-powered tarot deck-78 visually consistent cards from text', 'Craft Your Deck lets you describe your vision in plain text and get a complete, print-ready 78-card tarot deck. The AI knows tarot symbolism, locks in your style through a Deck Bible, and keeps every card visually consistent. For Etsy sellers, hobbyists, gift givers, or anyone with a vision.', 'https://ph-files.imgix.net/6940de68-e16c-4a52-96e9-9634de615d67.png?auto=format', 'https://www.producthunt.com/r/PDLMLBBNQU4DOH?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/PDLMLBBNQU4DOH?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'design', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:35.320Z', NULL, NULL, 'manual', NULL)
