VALUES ('46483b05-969d-4cbc-b8c4-911b023b2a2e', 'Recus.app', 'recus-app', 'App  onboarding without App Store releases', 'Every time your pm wants to change onboarding - add a field, change a screen, make something mandatory - it becomes a jira ticket, a pr, and weeks waiting for app store review. recus fixes that. install one sdk, wrap your app with recusappprovider, and control onboarding from a dashboard. pm changes a field, hits publish, and it’s live in 60 seconds. no code. no release. no ticket. react native sdk, customizable ui, server-driven schema, and a flow builder dashboard - all included.', 'https://ph-files.imgix.net/29d64275-ac7d-4ba9-85fd-bb06e7c4c5d4.png?auto=format', 'https://www.producthunt.com/r/YXQSG3ZYXBONB5?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/YXQSG3ZYXBONB5?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'design', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 4, 0, 2, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:35.327Z', NULL, NULL, 'manual', NULL)
