VALUES ('e65fb2f3-11ab-4cc5-b9a1-c5da7c91d4e6', 'Ranki.io', 'ranki-io', 'Grow your AI Search & Google visibility on Autopilot', 'Ranki helps founders, agencies, and creators grow visibility across Google and AI search—without hiring an SEO team. It analyzes your site and competitors, finds keyword gaps, and publishes daily branded articles designed to earn citations from ChatGPT, Perplexity, Gemini, Google AI Overviews, and search engines. Connect WordPress, Ghost, Shopify, Webhook, or Email, bring your own AI API key, and let Ranki turn your website into a traffic engine on autopilot.', 'https://ph-files.imgix.net/f09684b9-9ce9-4a25-a64f-3df22d414fdd.png?auto=format', 'https://www.producthunt.com/r/D42XR3A4SDDDJB?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/D42XR3A4SDDDJB?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'marketing', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:45.106Z', NULL, NULL, 'manual', NULL)
