VALUES ('17d551af-f45a-493a-8f0c-19a08a0c57fa', 'GSEO Editor | Full suite GEO+SEO editor', 'gseo-editor-full-suite-geo-seo-editor', 'The editor that guides you to 100% GEO + SEO-proof content ', 'GSEO Editor is built for today’s search reality, where AI engines like ChatGPT, Gemini and Perplexity decide what gets seen. It scores your content in real time for both Google ranking and AI citation as you write. One editor, one unified score: SEO, GEO, E-E-A-T and readability. With suggestion-first AI, full visibility into AI mentions, and no auto-rewrites, you improve rankings and get cited without losing your voice.', 'https://ph-files.imgix.net/5d256172-88f2-4af4-905d-01297019ab41.png?auto=format', 'https://www.producthunt.com/r/7JFVWFBHT64G4X?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/7JFVWFBHT64G4X?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'marketing', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:45.121Z', NULL, NULL, 'manual', NULL)
