VALUES ('ae85094d-c8b5-4a09-82c1-4820a8ac7cd1', 'Qollaby', 'qollaby', 'The Social Platform for Entrepreneurs & Community ', 'Qollaby brings local posts, events, auctions, rentals, services, and business promotions into one community-driven app. Discover what’s happening nearby, connect with others, buy and sell, message directly, and promote your brand — all from one feed. Build your profile, grow your network, and engage with your local community without switching between multiple apps. Best of all it’s free to post and search. Join the community today for free!', 'https://ph-files.imgix.net/09d80dbd-e826-4e21-8536-d635a9c9466e.png?auto=format', 'https://www.producthunt.com/r/6TZ2VNPHXK776S?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/6TZ2VNPHXK776S?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'marketing', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:45.141Z', NULL, NULL, 'manual', NULL)
