VALUES ('51d02cc1-719c-4760-9e85-3786f50ba80d', 'Connector.wtf', 'connector-wtf', 'Plug Google Ads, Meta & LinkedIn into your AI chat. Free', 'Plug Google Ads, Meta & LinkedIn into your favorite AI chat...for Free! Connector.wtf is a free, read-only MCP server that plugs your ad accounts directly into ChatGPT or Claude. Currently live: Google Ads, Meta Ads, and LinkedIn Ads. More connectors are on the way we''re building the ones our agency and our clients actually use. Free, because hosting it for the world costs roughly nothing and the alternative is everyone wrestling with CSV exports for the rest of their lives.', 'https://ph-files.imgix.net/c042b179-919c-43b9-815d-4beed5dee672.svg?auto=format', 'https://www.producthunt.com/r/MOIAXLLVMOYEF7?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/MOIAXLLVMOYEF7?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'marketing', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 6, FALSE, FALSE, TRUE, FALSE, 'active', 69, 6, 34, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:45.149Z', NULL, NULL, 'manual', NULL)
