VALUES ('6b67efc8-4ea4-4ba5-b598-d406a1f26b8d', 'Scoutr', 'scoutr', 'Listen. Act. Test. Learn. The AI marketing loop for DTC.', 'DTC founders spend their week guessing. What customers want, what competitors are doing, which ad will work. Scoutr replaces the guessing with a loop. Reads 50,000+ buyer signals daily across Reddit, Amazon, Trustpilot, Google, TikTok and 25+ sources. Writes your emails, ads, and replies in your buyer''s voice. Tests variants against synthetic personas before you spend. Gets sharper every week. Listen. Act. Test. Learn. From $197/mo.', 'https://ph-files.imgix.net/2b187d92-7286-4267-ba7d-29625b64b48b.png?auto=format', 'https://www.producthunt.com/r/C3UPHR5DVQ3AD6?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/C3UPHR5DVQ3AD6?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'marketing', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:45.201Z', NULL, NULL, 'manual', NULL)
