VALUES ('47e1b203-0357-4a08-a562-5d70ddfd80ff', 'Ipatee', 'ipatee', 'Turn any website into an AI agent in 60s,your website, alive', 'Ipatee transforms any website into an AI-powered customer agent. Just paste your website URL, and Ipatee automatically learns your business, generates an AI assistant, and helps you answer customers 24/7. No coding. No training. No complicated setup. Perfect for: • local businesses • startups • creators • agencies • crypto projects • online services Your website should not be static anymore. With Ipatee, your website becomes alive.', 'https://ph-files.imgix.net/093bb6c2-8a72-4897-b406-d55dcf1aa38f.png?auto=format', 'https://www.producthunt.com/r/VGR5MHKQJ5MG5S?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/VGR5MHKQJ5MG5S?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'automation', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:48.732Z', NULL, NULL, 'manual', NULL)
