VALUES ('da0c27ea-53f3-4970-aebf-26c74478b64f', 'Synkd', 'synkd', 'An AI-built website that keeps itself in sync', 'Synkd turns your Google Business Profile into a beautifully designed website in under 2 minutes — and keeps it in sync every day, automatically. Update your hours on Google? Your site updates too. New photos? They appear in your gallery overnight. Closed for a holiday? Synkd reflects it before customers see stale info. Built for restaurants, salons, clinics — any SMB tired of website-rot. • modern responsive design • Daily Google sync (the magic) • Free synkd.dev subdomain or bring your own', 'https://ph-files.imgix.net/c5f0c4fe-c1f7-4428-a7cc-728194782c82.png?auto=format', 'https://www.producthunt.com/r/XSCN2VJ6DCX4QY?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/XSCN2VJ6DCX4QY?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'marketing', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:48.782Z', NULL, NULL, 'manual', NULL)
