VALUES ('714fd166-7936-4669-9a16-7580beef1a95', 'Framer Extractor', 'framer-extractor', 'No Framer bill. No catch. Just grab it ', 'Framer Extractor lets you download any Framer website as a fully self-hosted static site with one click. It extracts all HTML, CSS, JavaScript, images, fonts, videos, cursors, and CMS content for offline use. URLs are automatically rewritten, Framer branding and analytics are removed, and CSS is cleanly exported. The final site works perfectly on Netlify, Vercel, Render, GitHub Pages, Cloudflare Pages, or any static hosting platform.', 'https://ph-files.imgix.net/f4ef8def-161b-4fd6-85a8-313ace74f474.png?auto=format', 'https://www.producthunt.com/r/KWXYUFSPAZBX7D?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/KWXYUFSPAZBX7D?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'design', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 1, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:48.798Z', NULL, NULL, 'manual', NULL)
