VALUES ('cd5218a2-9004-472f-b347-aaeb25e9f63d', 'AILabeling', 'ailabeling', 'Create custom size PDF labels from Google Sheets data', 'Most businesses already manage product data in spreadsheets, but still create labels manually in separate software. AILabeling turns Google Sheets into a label generation system: design templates, connect fields to columns, generate barcode and QR labels, and export print-ready PDFs with exact dimensions — all without leaving Sheets.', 'https://ph-files.imgix.net/c9a4c47c-6c24-46a9-b7ce-2f51ab7cb367.png?auto=format', 'https://www.producthunt.com/r/NNUVCH75V4BYXW?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/NNUVCH75V4BYXW?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'design', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:48.807Z', NULL, NULL, 'manual', NULL)
