VALUES ('fa1fa40e-8b2c-4b19-88b5-f18612fadc5e', 'AI App Builder for kintone', 'ai-app-builder-for-kintone', 'Build kintone apps from photos — instantly', 'Transform inspection sheets, invoices, and checklists into kintone apps instantly. Upload a photo → Claude AI analyzes it → Complete app with all fields configured. No coding required. Perfect for kintone users who spend hours on manual app setup. Features: - Photo-based app generation - AI-powered field detection - Supports text, numbers, dates, checkboxes - One-click deployment - $49 lifetime license Save hours of manual configuration work.', 'https://ph-files.imgix.net/50ae49da-2823-436b-9121-bbee7c718e47.png?auto=format', 'https://www.producthunt.com/r/PLRIKVTIW7CS67?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/PLRIKVTIW7CS67?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'productivity', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 2, 0, 1, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:48.815Z', NULL, NULL, 'manual', NULL)
