VALUES ('7a4c7eb6-baff-4d72-a3a4-c53789040a82', 'AnalyZ Solutions', 'analyz-solutions', 'Analyze data and transcripts without paying a penny', 'Most researchers and students are forced to pay hundreds for desktop software or spend months learning to code just to analyze data. AnalyZ Solutions changes that. Upload datasets or interview transcripts and get insights in seconds — no coding, no statistics degree, no credit card required. Quantitative and qualitative analysis in one free platform. Your data is never stored on our servers — everything is processed in your browser and discarded when you close the tab. No catch.', 'https://ph-files.imgix.net/36ae360a-bc4e-4540-b624-7faa3f89315a.png?auto=format', 'https://www.producthunt.com/r/SO7IBPDIKOWDP7?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/SO7IBPDIKOWDP7?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'automation', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 1, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:48.824Z', NULL, NULL, 'manual', NULL)
