VALUES ('6dc6de75-6288-479f-a895-408dc34ac97a', 'MESA', 'mesa', 'Describe your Shopify workflow. MESA builds it.', 'For Shopify merchants buried in repetitive store operations, MESA turns plain-English requests into automations that work across their existing tools. Unlike more DIY automation platforms, MESA is built for teams that want outcomes, not workflow complexity. Describe what you need, and MESA helps automate the busywork behind orders, inventory, fulfillment, and customer support.', 'https://ph-files.imgix.net/6775009f-d8fa-4b86-9a15-ed844696e847.png?auto=format', 'https://www.producthunt.com/r/2YSQH4VYVZVYWJ?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/2YSQH4VYVZVYWJ?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'writing', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '7.50', 23, FALSE, FALSE, TRUE, FALSE, 'active', 230, 23, 115, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:48.841Z', NULL, NULL, 'manual', NULL)
