VALUES ('fcbad160-01e8-494e-a2e1-b1567346d667', 'Data to Visuals', 'data-to-visuals', 'Upload a spreadsheet. Get a dashboard. Done.', 'Free browser-based dashboard builder for spreadsheet users. Upload any CSV or Excel file and: → Build dashboards with drag-and-drop charts → Configure with clicks — no formulas, no code → Export as PDF or PNG in one click → Save and resume your workspace anytime Your data never leaves your browser. No account. No server. No subscription. Built for anyone who wants better visuals from their spreadsheets without paying for Tableau or Power BI.', 'https://ph-files.imgix.net/5bbd08c8-e3eb-4ca8-bce4-ca4ccaa17da0.svg?auto=format', 'https://www.producthunt.com/r/NRXMPNVQTXAFTL?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/NRXMPNVQTXAFTL?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'productivity', ARRAY['new','product-hunt']::text[], 'paid', ARRAY[]::text[], FALSE, FALSE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 3, 0, 1, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:48.848Z', NULL, NULL, 'manual', NULL)
