VALUES ('0a43c522-531e-4d81-bade-ee0ac0641918', 'WrightTest: Open Source QA', 'wrighttest-open-source-qa', 'Open-source, self-hosted no-code UI for Playwright', 'WrightTest is an open-source, self-hosted automation platform built on Playwright. It enables teams to create and execute UI tests through a visual interface without writing code. Key features include a robust recorder with manual locator editing, mobile emulation, and a centralized dashboard for test management. Unlike SaaS alternatives, it offers clean code export (JS/TS), scheduled runs, and real-time alerts via Slack/Telegram, all while keeping your data private in your own infrastructure.', 'https://ph-files.imgix.net/7007a1c6-4f36-472a-aeb6-8f2d5dfccdf5.png?auto=format', 'https://www.producthunt.com/r/KGIH64NEKZFLRD?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/KGIH64NEKZFLRD?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'code', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'free', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:48.864Z', NULL, NULL, 'manual', NULL)
