VALUES ('b6452894-9907-4ce9-83d3-7badabdb0dfe', 'Impulse AI', 'impulse-ai', 'From plain English to deployed ML model in an hour', 'Impulse is an autonomous ML engineer. Describe a prediction problem in plain English, connect your data, get a deployed model with an API in under an hour. Our agent placed top 2.5% on a Kaggle competition. 782 of 31,791, with zero human intervention. No prompt engineering, no tuning. AutoML tools need configuration. No-code builders stop at a trained model. Impulse handles the full workflow: cleaning, feature engineering, model selection, leakage checks, deployment, and monitoring.', 'https://ph-files.imgix.net/8ad2038b-a4ea-4827-a919-5533d82e9ade.png?auto=format', 'https://www.producthunt.com/r/2KQHK5FAJ5IBU7?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/2KQHK5FAJ5IBU7?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'code', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 19, 1, 9, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:48.880Z', NULL, NULL, 'manual', NULL)
