VALUES ('34328872-a132-4c05-acfd-bbedd93e0cc8', 'hire.page', 'hire-page', 'Launch a careers page with a built-in ATS in 5 minutes', 'hire.page helps startups, SaaS companies, agencies, and small teams launch a branded careers page with a built-in ATS. Create job posts, collect applications, manage candidates on a visual pipeline, write job descriptions with AI, and send automated candidate emails — without buying an enterprise ATS.', 'https://ph-files.imgix.net/15d10695-6627-44d8-8917-7ab693d4f6a0.png?auto=format', 'https://www.producthunt.com/r/57WEOGS3MZ7ZSY?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/57WEOGS3MZ7ZSY?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'automation', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 3, 0, 1, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:48.887Z', NULL, NULL, 'manual', NULL)
