VALUES ('9f34c7db-0be7-4740-83e1-8435ae95729e', 'Talk&Buy', 'talk-buy', 'Shop together in 2D online stores.', 'Talk&Buy reimagines online shopping as a 2D visual experience where products are instantly visible instead of hidden in menus and category trees. Stores run directly in the browser with no login or downloads required. It adds a social layer where merchants can see and talk to visitors in real time, and shoppers can interact with each other, turning stores into living, community-driven spaces that help increase engagement and understanding of customer behavior.', 'https://ph-files.imgix.net/9d3c70b8-cc49-473a-9b71-0b78886f0126.png?auto=format', 'https://www.producthunt.com/r/IVT4ZJELNHTF4A?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/IVT4ZJELNHTF4A?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'automation', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 1, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:48.895Z', NULL, NULL, 'manual', NULL)
