VALUES ('3fb3527c-c721-438c-90a0-5c027e95e26e', 'ConvertoAI', 'convertoai', 'Chat to build AI agents for anything  no code, no limits', 'Convertoai lets you build AI agents by simply chatting. No code, no flowcharts, no complexity. Just describe what you want your agent to do it comes to life instantly. Sales agent, support agent, lead qualifier, appointment booker, onboarding assistant anything. Deploy across every channel website, WhatsApp, email, and voice calls. Connects to your website, PDFs, FAQs, and APIs. Every conversation captures leads, logs interactions, and knows exactly when to hand off to a human.', 'https://ph-files.imgix.net/103ff8d3-b5ba-4972-8a96-22d438ea47a8.png?auto=format', 'https://www.producthunt.com/r/EX6IQSAHFOWV2W?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/EX6IQSAHFOWV2W?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'productivity', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 1, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:48.901Z', NULL, NULL, 'manual', NULL)
