VALUES ('304752c3-6c5a-413e-a7bf-37fe9d9f33e1', 'FC Digital - AI Automation Pack', 'fc-digital-ai-automation-pack', 'Telegram AI agents & prompts for small businesses', 'I built AI agents on Telegram for barbershops, restaurants, and riads — fully automated bookings and customer messages. Now I sell the prompts and systems so you can do the same without coding: - Claude Code Prompt (Telegram agent) — €147 - Claude Mastery Pack (10 prompts) — €127 - Ultimate Claude Prompt Pack — €197 - Freelance OS in Claude Code — €97 Built with N8N, Claude AI, and Telegram. No coding required.', 'https://ph-files.imgix.net/e63d8f0a-d520-4ef6-83ae-375b60a42dc4.jpeg?auto=format', 'https://www.producthunt.com/r/AEL5TQVXWBPN6M?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/AEL5TQVXWBPN6M?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'productivity', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 1, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:48.916Z', NULL, NULL, 'manual', NULL)
