VALUES ('d04e211b-7f3f-414b-8e86-fb044cf25bc1', 'demoin72', 'demoin72', 'Working app demos delivered in 72 hours', 'I build fully functional app and tool demos for marketing, ops and product teams delivered in 72 hours. Working apps your stakeholders can use in the room to get the sign-off from management. My background in advertising and marketing, rather than tech and code, gives me a unique advantage. I understand branding and UX, and build apps that are bespoke to the client''s company and feel homegrown. I charge a flat fee, there''s no retainer and I hand over the source code.', 'https://ph-files.imgix.net/3c7e5795-6c6a-4401-a48b-2660bca4a0bf.x-icon?auto=format', 'https://www.producthunt.com/r/O7WALPUWKATYVY?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/O7WALPUWKATYVY?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'automation', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 3, 0, 1, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:48.925Z', NULL, NULL, 'manual', NULL)
