VALUES ('0f365382-2bf0-45d1-9aa5-574ee68cd43e', 'DialogForm', 'dialogform', 'AI-powered conversational forms that boost completion', 'DialogForm turns traditional forms into natural, conversational experiences. Instead of building forms manually, simply describe what you want to collect—DialogForm generates the questions, logic, and validation instantly using AI. Design, customize, and publish chat-style forms that feel intuitive on both mobile and desktop. Improve completion rates, reduce drop-offs, and collect better data without friction. Perfect for surveys, lead generation, onboarding, and feedback collection.', 'https://ph-files.imgix.net/5de9c5f2-14bf-4f5b-bda5-ba8e1340454f.svg?auto=format', 'https://www.producthunt.com/r/K44SXKHHVVKV2V?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/K44SXKHHVVKV2V?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'productivity', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 1, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:48.932Z', NULL, NULL, 'manual', NULL)
