VALUES ('5783bc41-ac11-4bef-bb7b-cb2815e38276', 'AgentBox — L''App Store des IA autonomes', 'agentbox-l-app-store-des-ia-autonomes', 'Build AI agents to automate your workflows', 'AgentHub is the hybrid marketplace where creators build, certify and monetize AI agents — and where teams discover, test in sandbox, and orchestrate them in visual workflows. Pay only for results. Shadow Learning makes every agent smarter with each correction.', 'https://ph-files.imgix.net/608beb19-80ff-4360-9422-f79a136fe537.vnd.microsoft.icon?auto=format', 'https://www.producthunt.com/r/EF7DMT4J56S6MS?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/EF7DMT4J56S6MS?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'writing', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 1, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:48.940Z', NULL, NULL, 'manual', NULL)
