VALUES ('f624a534-7c39-4759-9c55-5c0226255db8', 'Wealthly', 'wealthly', 'Budget tracker — no subscription, no account needed', 'Most finance apps are bloated, expensive, or harvest your data. Wealthly is different — it runs entirely in your browser, stores everything locally on your device, and costs a one-time fee of $15. Track income, expenses, savings and net worth in one place. Set monthly goals, reconcile balances, export to CSV, and see spending patterns with a monthly chart. Supports USD, EUR, GBP, CHF and RON. No account. No subscription. No data sent anywhere. Works on phone, tablet and desktop.', 'https://ph-files.imgix.net/8aa720b8-e2ed-42a4-95b3-7d21d1aabc70.jpeg?auto=format', 'https://www.producthunt.com/r/35OHEYBJSDEGND?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/35OHEYBJSDEGND?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'productivity', ARRAY['new','product-hunt']::text[], 'paid', ARRAY[]::text[], FALSE, FALSE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 1, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:48.948Z', NULL, NULL, 'manual', NULL)
