VALUES ('816658c5-50d5-4d4d-ace8-2ae97c243744', 'AI APP STUDIO', 'ai-app-studio', 'From Prompt to Deployable App in Minutes', 'AI Apps Studio helps you turn a simple prompt into a real, deployable mobile app. Just describe your idea in plain language and the platform generates the app structure, screens and core features for you. It is built for founders, business owners and non-technical teams who want to move fast without starting from scratch. Create, preview, refine and prepare your app for launch with a faster, simpler way to build.', 'https://ph-files.imgix.net/f2a838a5-6d0e-457d-95d8-fc2916a81403.svg?auto=format', 'https://www.producthunt.com/r/MADN7CH4IDISIC?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/MADN7CH4IDISIC?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'code', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 1, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:48.963Z', NULL, NULL, 'manual', NULL)
