VALUES ('f46f471d-803b-441c-8db4-6e174cc43284', 'QRGenHub', 'qrgenhub', 'Free QR Code Generator with Logo — No Signup, No Limits', 'QRGenHub lets you create custom QR codes in seconds — with your logo, brand colors, and no account required. Supports URL, WiFi, vCard, Phone, SMS, and Email. Free forever. No expiration. Most QR generators make you: create an account → verify email → choose a plan → then maybe let you download. QRGenHub: open page → enter link → download. That''s it. 30 seconds. No friction.', 'https://ph-files.imgix.net/800ec045-0762-428a-8cf6-9fc740c30f8b.png?auto=format', 'https://www.producthunt.com/r/AOUMRTV4KEOA6N?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/AOUMRTV4KEOA6N?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'design', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'free', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 2, 0, 1, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:48.971Z', NULL, NULL, 'manual', NULL)
