VALUES ('a75bc98d-4714-40ae-8e88-26274b60027c', 'CompoTe', 'compote', 'Docker Compose UI for building and sanity-check infra stacks', 'Compote lets you build and manage Docker Compose setups through a point-and-click UI and export a ready-to-deploy ZIP bundle. Features: * Validation — real-time rule-based checks catch misconfigured services before you deploy * Connectivity tracking — detects port conflicts, missing network links, unresolved service dependencies, and cross-project collisions * Visual service editor * Import Your own infra * Built-in library and registry search * Multi-host management', 'https://ph-files.imgix.net/0cb1df26-e900-4cf6-98a1-42379cb63519.png?auto=format', 'https://www.producthunt.com/r/HN5ZKOF4HWBLP4?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/HN5ZKOF4HWBLP4?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'code', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 4, 0, 2, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:49.008Z', NULL, NULL, 'manual', NULL)
