VALUES ('28cc1f56-7298-487a-aac4-cfbcf62ce057', 'WhisperStudio', 'whisperstudio', 'Fast Local AI Transcription For Windows', 'KinoFlux Whisper Studio operates as a current-generation transcription environment for desktop systems, built using OpenAI Whisper technology. Subtitles emerge through local processing of sound and moving image files, handled entirely within personal computing hardware. Privacy remains embedded by design - no external transmission occurs during operations. Each task unfolds where it begins: on one device, under user control.', 'https://ph-files.imgix.net/0b44525f-a045-4eba-aebe-8d5326a1734b.png?auto=format', 'https://www.producthunt.com/r/M44DE3D4KKSCEV?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/M44DE3D4KKSCEV?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'video', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:51.786Z', NULL, NULL, 'manual', NULL)
