VALUES ('45eee9cb-33d9-4624-ba5a-be732bac822f', 'Recast', 'recast', 'High-performance open-source product demo creator tool', 'Recast is a high-performance fully open-source screen recording tool with integrated, cinematic editing capabilities. It aims to replace messy timeline-based tools with a "Smooth by Default" experience for startups and creators generating polished product demos.', 'https://ph-files.imgix.net/c435e6d7-bc32-4e18-ae59-9f3c03cbe418.png?auto=format', 'https://www.producthunt.com/r/MOQAHF5H7KNBVA?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/MOQAHF5H7KNBVA?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'video', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'free', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 1, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:51.856Z', NULL, NULL, 'manual', NULL)
