VALUES ('8de00616-9bc3-4cec-9633-08993afcfef7', 'TraceVid', 'tracevid', 'AI search for exact clips in your local video library.', 'TraceVid is a local-first desktop app for creators who need to find exact moments in old video footage. Unlike cloud-first archive tools or generic AI chat apps, it starts with retrieval: import videos from local folders, NAS-backed archives, or supported URLs, search by transcript and visual content, recover exact clips, then ask AI about selected video evidence instead of starting from a blank prompt.', 'https://ph-files.imgix.net/3f2579d8-cc87-491f-9d90-5cd2b4dc9597.png?auto=format', 'https://www.producthunt.com/r/74N7JJ2ZUJ6Q22?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/74N7JJ2ZUJ6Q22?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'productivity', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:51.864Z', NULL, NULL, 'manual', NULL)
