VALUES ('42fd3320-be38-4511-8541-24dd7a69b6c9', 'AIVantage', 'aivantage', 'AI-powered video editing tools for social media creators', 'AIVantage brings 14 AI-powered video tools under one roof — built for social media creators who are serious about growth. Add subtitles in 90+ languages, remove silences and filler words, clip and stitch highlights, resize for every platform, remove backgrounds, generate thumbnails, and more. No software to install. No account required to get started. Free to use. Built by a solo founder who got tired of switching between 10 different tools.', 'https://ph-files.imgix.net/180c1a61-aab9-405c-9cc5-230573c36827.png?auto=format', 'https://www.producthunt.com/r/JVXJZPDII5ITEE?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/JVXJZPDII5ITEE?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'writing', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:51.871Z', NULL, NULL, 'manual', NULL)
