VALUES ('5f94a553-482b-40ff-a79f-26646b4c05b2', 'SRTGen.com', 'srtgen-com', 'Professional AI Subtitles for Your Viral Videos', 'We’re SRTGen.com — a professional AI subtitle generator & editor built to make beautiful animated subtitles fast, affordable, and effortless. X Integration Mention @SRTGenDotCom on any post on X, and we’ll subtitle or translate the video directly for you. SRTGen is perfect for creators, clips, podcasts, interviews, tutorials, and short-form content. ✅ Powerful & Easy-to-Use Subtitle Editor ✅ Accurate Word-Level Precision ✅ Affordable Pricing — One of the Cheapest on the Market', 'https://ph-files.imgix.net/afed5451-b98d-4436-97c0-9f83bcaeea9f.png?auto=format', 'https://www.producthunt.com/r/HBSTW6KPIPDTGL?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/HBSTW6KPIPDTGL?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'marketing', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 1, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:51.878Z', NULL, NULL, 'manual', NULL)
