VALUES ('a47a91fe-50fb-424a-9ed0-aa4d0704852d', 'Cenvero Cetus', 'cenvero-cetus', 'Render HTML to video. One binary. Zero dependencies.', 'Cetus is a self-contained HTML-to-video renderer. Write HTML with CSS animations, GSAP, Three.js, or WebGL — Cetus captures every frame with bundled headless Chrome and pipes it through bundled ffmpeg. No Node.js, npm, system Chrome, or ffmpeg needed. One binary. Same HTML produces identical video on any machine, every time. Ships with a Build with AI page to generate ready-to-render compositions via Claude, ChatGPT, or any AI agent.', 'https://ph-files.imgix.net/8eb5ffa5-60ee-4e44-a943-567949d7bba0.png?auto=format', 'https://www.producthunt.com/r/TDFSTUXUTZ63CC?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/TDFSTUXUTZ63CC?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'code', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 3, 0, 1, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:51.885Z', NULL, NULL, 'manual', NULL)
