VALUES ('8738fefe-5773-4003-85ac-2dc64520c6f8', 'Creative Lounge Studio presents Beatsync', 'creative-lounge-studio-presents-beatsync', 'Sync Your Story to the Perfect Beat.', 'Creative Lounge Studio launches BeatSync — an AI-powered tool that automatically syncs your raw video clips to any music track in seconds. Upload your clips, drop in your track, and watch your footage snap into a perfectly timed, beat-synced sizzle reel. No editing experience needed. No expensive software. Just cinematic results — fast. Only 30 spots available for our 30-day free beta trial. No credit card required. After your trial, just $9/mo. See it in action on https://creativelounge.studio/', 'https://ph-files.imgix.net/242fe143-7069-4548-93bc-83d4b4b85d3f.png?auto=format', 'https://www.producthunt.com/r/WV2DAEZKPRPNOW?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/WV2DAEZKPRPNOW?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'productivity', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 2, 0, 1, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:51.908Z', NULL, NULL, 'manual', NULL)
