VALUES ('2507cc6d-01b2-4108-b9a2-21a5382a31df', 'ADVIDS', 'advids', 'Remote Video Creation Made Easy', 'Advids is an online video studio built for remote collaboration, giving teams everywhere access to cinematic-quality animated video production without the complexity or cost of a traditional agency. Work with a dedicated team, Creative Director, Scriptwriter, Animators. Track milestones, share feedback, approve deliverables, and manage revisions all in one place, from anywhere in the world. Just bespoke, high-quality animation delivered through a seamless remote production experience.', 'https://ph-files.imgix.net/ca6b2434-bc84-41e3-bb35-8729a98aaf47.png?auto=format', 'https://www.producthunt.com/r/CFQRPUIVBIUQCJ?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/CFQRPUIVBIUQCJ?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'marketing', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:51.916Z', NULL, NULL, 'manual', NULL)
