VALUES ('da41856f-3cc0-40a4-8269-fb7bd7387af0', 'Video API Hub', 'video-api-hub', 'Video generation APIs for developers / no code devs', 'Video API Hub lets developers generate cinematic videos, reels, thumbnails, and animated content using simple JSON APIs — without managing FFmpeg infrastructure. Define videos as JSON, render via API. Templates, animations, motion graphics. Works with n8n, Zapier, Make.', 'https://ph-files.imgix.net/17e1af17-307e-4102-81b4-7619512f742a.svg?auto=format', 'https://www.producthunt.com/r/3ZFMAFWKEPE2CU?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/3ZFMAFWKEPE2CU?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'video', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 3, 0, 1, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:51.956Z', NULL, NULL, 'manual', NULL)
