VALUES ('93be85e8-5e2f-4346-8ed0-e752307e6d5d', 'SnatchTik', 'snatchtik', 'Download TikTok videos free no watermark, no login, instant', 'SnatchTik is a free TikTok video downloader that removes watermarks instantly — no account, no app, no limits. Paste any TikTok URL and download as MP4 or MP3 in original quality within seconds. Works on all devices — iPhone, Android, and desktop. Why SnatchTik? No watermark on downloaded videos MP4 + MP3 support 100% free, no registration No daily limits Works on any browser and device', 'https://ph-files.imgix.net/15b04d8a-6e4a-4f25-b391-1a7439baa796.png?auto=format', 'https://www.producthunt.com/r/EWUNYR5PK4CIQO?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/EWUNYR5PK4CIQO?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'productivity', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:51.970Z', NULL, NULL, 'manual', NULL)
