VALUES ('1d4d4621-9e57-4fff-9c47-f0322719a926', 'LyricTune', 'lyrictune', 'From audio file to TikTok lyric video in minutes', 'LyricTune turns your song into a handful of TikTok-ready lyric videos in minutes. Upload your audio, auto-transcribe or manually sync lyrics, pick a background pack (anime, VHS, nature + more), and export an MP4 ready to post. Built for indie artists doing everything solo. No designer, no After Effects, no CapCut repetitive hell. I built this after using lyric videos to grow from near-zero to 30k Spotify monthly listeners in 28 days. Now any artist can do the same.', 'https://ph-files.imgix.net/80f8f413-06a4-421e-9b73-041d394b507e.png?auto=format', 'https://www.producthunt.com/r/GZLIDCUKNU5CCW?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/GZLIDCUKNU5CCW?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'marketing', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:51.984Z', NULL, NULL, 'manual', NULL)
