VALUES ('97dc60dd-f44c-4a9b-a844-9349cdf0ce83', 'Firassa Studio', 'firassa-studio', 'AI assistant editor that builds first cuts inside Premiere', 'Firassa is an AI-native assistant editor inside Adobe Premiere Pro for professional video teams. It does the work before the creative edit: logging raw footage, organizing scenes, finding story moments, pulling selects, answering questions, and building first cuts on the Premiere timeline. It turns projects into timecoded video memory — people, scenes, dialogue, locations, emotions, actions, and story beats — so every answer and cut is source-traceable. Editors approve before anything lands.', 'https://ph-files.imgix.net/536756fc-e4d8-457d-a3e5-8164b17f4e3d.png?auto=format', 'https://www.producthunt.com/r/QD45MYG4M6AZCT?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/QD45MYG4M6AZCT?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'writing', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 6, FALSE, FALSE, TRUE, FALSE, 'active', 62, 6, 31, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:51.991Z', NULL, NULL, 'manual', NULL)
