VALUES ('5a9ef400-2556-45dc-a059-0650078046dd', 'AICW Video', 'aicw-video', 'Open-source AI agent for editing video interviews', 'AICW Video is open-source AI agent for editing video interviews with humans: - auto-matches and auto-syncs a separately recorded audio - auto-generates captions - privacy: detects and blurs faces / replaces with emoji - privacy: replace original speaking into computer-generated voice - suggests short clip moments - exports to TikTok, Instagram Reels, YouTube Shorts, and LinkedIn. - live preview for every option - Works as a standalone app - Works as a skill/MCP for Claude, ChatGPT, and Codex.', 'https://ph-files.imgix.net/1464f897-633f-4eda-a47f-409274c39c42.png?auto=format', 'https://www.producthunt.com/r/Y7UVDI77GWHZYQ?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/Y7UVDI77GWHZYQ?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'marketing', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'free', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 1, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:39:52.006Z', NULL, NULL, 'manual', NULL)
