VALUES ('dcc7e143-b295-4bf7-a992-dd57bd8f99a8', 'Your books finally have a witty narrator', 'your-books-finally-have-a-witty-narrator', 'AI narrates books + comments, 4 langs', 'Problem: Audible is costly, limited, monotonous. Reading is slow. Solution: Book v2 Audio – free open-source desktop app (Win/Linux). Takes FB2/EPUB, splits into sentences, inserts AI commentary between them (DeepSeek, ChatGPT, Grok, Qwen), synthesizes to speech (Edge TTS or Piper), saves as MP3. Uniqueness: AI comments with personality. Choose: Porfiry Petrovich (sarcastic detective), Strict Critic, Enthusiastic Fan, Scientific Expert, or custom prompt.', 'https://ph-files.imgix.net/ba26a1e1-a9d8-4263-b583-1afdbd09d009.jpeg?auto=format', 'https://www.producthunt.com/r/MUMA3RADSX6RQT?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/MUMA3RADSX6RQT?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'audio', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'free', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:40:01.098Z', NULL, NULL, 'manual', NULL)
