VALUES ('bf942e91-dd52-4f4c-bc4d-7ab6cfc47c83', 'WhisperLink Voice', 'whisperlink-voice', 'Communication Audio iOS Productivity Social', 'WhisperLink is an iOS app built for real world noisy environments like cafés, bars, concerts, airports and crowded streets. Instead of trying to fight background noise, it lets two people hear each other directly through headphones with very low latency audio. It also includes a local Bluetooth/WiFi mode for nearby communication without internet, plus a simple nearby emergency mesh chat feature.', 'https://ph-files.imgix.net/223aecf8-7bef-4f82-96e4-b74880f71986.png?auto=format', 'https://www.producthunt.com/r/SMWB5ZPTNRPZ2T?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/SMWB5ZPTNRPZ2T?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'audio', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 1, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:40:01.106Z', NULL, NULL, 'manual', NULL)
