VALUES ('f478c8a6-424f-4e26-bd5a-5660b52910f1', 'Azalea Labs', 'azalea-labs', 'Unlimited Audiobooks, Podcasts, and Spoken Word Content', 'We''ve taken most major public domain books and brought them to life with voice AI models, in one application that lets you listen to audiobooks, podcasts, and blogs in audio form. We''re even working with authors and publishers to bring their catalogs to life. No limits, no credits, (no music), and tons of features specifically for spoken word audio, like transcripts and karaoke. More features (like notes and AI Q&A) coming soon! Currently only available on iOS.', 'https://ph-files.imgix.net/0cfb2e34-8f19-4612-b450-d99241662ad0.png?auto=format', 'https://www.producthunt.com/r/O6ZSCI4OV3S7Y7?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/O6ZSCI4OV3S7Y7?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'audio', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:40:01.150Z', NULL, NULL, 'manual', NULL)
