VALUES ('a289cec6-855f-4292-a5ec-f55ca16be82a', 'Sound Warden', 'sound-warden', 'Automatically routes each app to the audio device you want', 'Every time I jumped between Spotify, Zoom, and YouTube I had to manually switch audio outputs. It drove me crazy. So I built Sound Warden. It lives in your menu bar and automatically routes each app to the audio device you want. Set it once, forget it forever. ✅ Per-app audio routing ✅ Menu bar — always accessible ✅ Lightweight, no background bloat Built for anyone who uses multiple audio devices daily.', 'https://ph-files.imgix.net/1634d526-2f8d-46b6-8f02-39792c90e1e6.png?auto=format', 'https://www.producthunt.com/r/6VXBIUM75ROBRY?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/6VXBIUM75ROBRY?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'audio', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 6, FALSE, FALSE, TRUE, FALSE, 'active', 63, 6, 31, '2026-05-12T00:00:00.000Z', '2026-05-12T01:40:01.163Z', NULL, NULL, 'manual', NULL)
