VALUES ('871141d7-9992-471e-82df-8a1b8f87ec6e', 'SHRP', 'shrp', 'Free speech-to-text. No login, no download.', 'SHRP is a free browser-based voice toolkit - no account needed, nothing to install. What you get: Live speech-to-text in 55+ languages (audio never leaves your device) AI file transcription with speaker labels and confidence highlighting Text-to-speech with 2,000+ Google Neural voices, download as MP3 YouTube to Text — extract captions as TXT, SRT, or VTT instantly Smart Voice Tools — turn transcripts into meeting notes and emails Privacy-first. No trackers, no session recording, no analytics.', 'https://ph-files.imgix.net/958a20b1-99f0-477a-9ab7-5d2575393ba9.png?auto=format', 'https://www.producthunt.com/r/U3WRXLCIU6HEFN?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/U3WRXLCIU6HEFN?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'productivity', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:40:01.171Z', NULL, NULL, 'manual', NULL)
