VALUES ('ddc75943-7925-46b9-b873-f8d68eb5151b', 'Phyrin', 'phyrin', 'Turns conversations into actionable insights', 'You record meetings, interviews, and podcasts — then never revisit them. Phyrin fixes that. Upload any audio or video file and get a structured briefing report in seconds: transcript, summary, key quotes, chapters, action items, and even a publishable article. Simple per-minute pricing, no subscription required.', 'https://ph-files.imgix.net/d1c1bf90-1aaf-4c97-aa68-a2738d437521.png?auto=format', 'https://www.producthunt.com/r/VQR3VZLBPMKFLC?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/VQR3VZLBPMKFLC?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'writing', ARRAY['new','product-hunt']::text[], 'paid', ARRAY[]::text[], FALSE, FALSE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:40:01.179Z', NULL, NULL, 'manual', NULL)
