VALUES ('bd13fc12-c457-4c9a-ae7d-f86eb479c10f', 'DockFm ', 'dockfm', 'Built For The Next Generation Of Broadcasters', 'DockFM is a professional, cloud-native radio automation suite designed for the modern era. Available for both macOS and Windows, it bridges the gap between traditional reliability and cloud flexibility. Key features: • Cross-platform: Native performance on Mac (M1/M2/M3) and Windows. • Cloud-managed playout: Your station stays live 24/7, even if your local hardware fails. • Professional DSP: EBU R128 loudness control for a perfect sound. Try it now: Register on our site to access the live demo!', 'https://ph-files.imgix.net/7ad254dd-df7d-4bf8-bafd-2d60b11ba02a.jpeg?auto=format', 'https://www.producthunt.com/r/ZUT4PMMW7EQCUJ?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/ZUT4PMMW7EQCUJ?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'writing', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:40:01.187Z', NULL, NULL, 'manual', NULL)
