VALUES ('1437f717-22bb-4cb6-aa30-eba7da3deff0', 'DeepCleanAudio', 'deepcleanaudio', 'AI-powered audio denoising that restores clarity in seconds.', 'AI Audio Denoiser lets you clean noisy audio in just one click. Powered by DeepFilterNet3, it intelligently removes background noise while keeping voices clear and natural—no complex setup required. Perfect for creators, developers, and everyday users, it supports batch processing and delivers fast, consistent results across multiple audio formats.', 'https://ph-files.imgix.net/f43795db-50b6-445c-9905-eafab90f03b7.png?auto=format', 'https://www.producthunt.com/r/RQMLKTTFCPTSZC?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/RQMLKTTFCPTSZC?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'audio', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 1, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:40:01.209Z', NULL, NULL, 'manual', NULL)
