VALUES ('aaaa9783-98b2-4f60-9e42-5c4b679e24cb', 'Revoxing Studio', 'revoxing-studio', 'AI voice generations: clone , translate, type, upload video.', 'Unlike raw TTS or dubbing tools, Revoxing Studio gives you full control: upload any video/audio → AI transcribes → you edit the transcript → translate with one click → generate with premium ElevenLabs voices. Or just type a prompt in any language. Free trial, no install. What’s different? Editable transcripts + audio prompt input + translation in one web app.', 'https://ph-files.imgix.net/a3ca97b7-1e5b-401e-b86e-3b9078071dd0.jpeg?auto=format', 'https://www.producthunt.com/r/5FIICFKIXTVSJ2?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/5FIICFKIXTVSJ2?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'audio', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:40:01.234Z', NULL, NULL, 'manual', NULL)
