VALUES ('cb09f652-dfb2-4d32-a763-e82ecba2e05f', 'SoloFreedom', 'solofreedom', 'Stop guessing what scale to play over your riffs', 'SoloFreedom detects the key of whatever you''re playing and shows you exactly what scales to solo with. Play a chord progression into your mic, get the key plus three scale recommendations with interactive fretboard diagrams showing all 5 box positions in tab and notation. Built for guitarists who want to stop guessing and start soloing. 3 free analyses, no account needed.', 'https://ph-files.imgix.net/8b9a9662-05c0-44a8-80af-8d2544935272.png?auto=format', 'https://www.producthunt.com/r/6G3JJGDPHKMT4A?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/6G3JJGDPHKMT4A?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'productivity', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 2, 0, 1, '2026-05-12T00:00:00.000Z', '2026-05-12T01:40:01.257Z', NULL, NULL, 'manual', NULL)
