VALUES ('9f6a0140-1f82-463e-9087-1e667538ef73', 'ssave.cc', 'ssave-cc', 'Save video and audio TikTok in seconds', 'SSave lets you download TikTok videos and audio instantly — no watermark, no app install, no account needed. Just paste the TikTok link → click download → done. ✅ Removes watermark automatically ✅ Extract audio as MP3 ✅ Works on mobile & desktop ✅ Supports 9 languages Built for creators, marketers, and anyone who wants to save content they love.', 'https://ph-files.imgix.net/efd68027-0f52-4eba-9fc9-a393005e1088.png?auto=format', 'https://www.producthunt.com/r/KLOZN7KCAXHNXU?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/KLOZN7KCAXHNXU?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'audio', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 1, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:40:01.265Z', NULL, NULL, 'manual', NULL)
