VALUES ('b69980ef-f78b-4f14-9d31-7dcc45855ca2', 'Whispy — Free Local Audio Transcription.', 'whispy-free-local-audio-transcription', 'Productivity, Privacy, Local, AI, Whisper, Transcription', 'Every transcription tool I could find uploads your audio to a cloud server. For journalists, lawyers, researchers, or anyone with sensitive recordings: that''s a real problem. Whispy is different because everything runs locally in your browser. The AI model downloads once and runs entirely on your device. Your audio never touches a server, not even for a millisecond. No account. No upload. No subscription. Free forever.', 'https://ph-files.imgix.net/0f526b5f-338d-494e-99f1-cacdb4d9abac.svg?auto=format', 'https://www.producthunt.com/r/HZA3UQUBSG6ZXV?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/HZA3UQUBSG6ZXV?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'audio', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'free', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 5, 0, 2, '2026-05-12T00:00:00.000Z', '2026-05-12T01:40:01.271Z', NULL, NULL, 'manual', NULL)
