VALUES ('77a301b5-1524-4bca-81c7-318eb63db8e1', 'RoomTuned', 'roomtuned', 'Fix your room acoustics from a single recording', 'RoomTuned analyzes your room acoustics from a short clap recording and turns it into a clear, actionable treatment plan. Upload a 5–7s recording from your phone and RoomTuned analyzes it and tells you what’s wrong and how to fix it with actionable treatment recommendations. No equipment, no technical knowledge. Results in about a minute. It’s designed for creators, podcasters, home studios, and anyone who wants to improve their room sound without wasting money on treatment based on guesswork.', 'https://ph-files.imgix.net/9afc9998-1937-43c1-944f-a9526acfdfab.png?auto=format', 'https://www.producthunt.com/r/PKLET35XAKXYHE?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/PKLET35XAKXYHE?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'writing', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 2, 0, 1, '2026-05-12T00:00:00.000Z', '2026-05-12T01:40:01.279Z', NULL, NULL, 'manual', NULL)
