VALUES ('9da32fb4-01f5-4454-ae4d-5f0448242adc', 'sweet sorrow — a voice beside you', 'sweet-sorrow-a-voice-beside-you', 'A 1-minute audio escape to lighten your heart and find peace', '"People are born, and people live. Even with struggles, a new world awaits." Life can be heavy. Whether you are dealing with daily anxiety, feeling lonely at night, or facing a moment of crisis, sometimes you just need one minute to breathe This minimalist web app is designed to provide instant mental relief through a "healing voice" message blended with the serene song of the Blue-and-white Flycatcher 1-Minute Experience: Designed for those seeking instant mental clarity', 'https://ph-files.imgix.net/dbc4fba3-770f-4802-bf9e-c124670129bc.png?auto=format', 'https://www.producthunt.com/r/F6GOMNCYXKVOUG?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/F6GOMNCYXKVOUG?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'audio', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 5, 0, 2, '2026-05-12T00:00:00.000Z', '2026-05-12T01:40:01.287Z', NULL, NULL, 'manual', NULL)
