VALUES ('19be7580-2b54-48df-8b2c-b3ed6705dae9', 'Listen2 Podcasts', 'listen2-podcasts', 'Great listening should never feel complicated.', 'Listen 2 is designed for people who love podcasts and want to jump straight into what they enjoy — no clutter, no endless menus. Your favourite shows appear the moment you open the app, so with just two taps, you’re right where you want to be — listening.', 'https://ph-files.imgix.net/a339f0df-d4d4-4590-8359-1632797cf48c.svg?auto=format', 'https://www.producthunt.com/r/VXWVSOBEVSG6NI?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/VXWVSOBEVSG6NI?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'audio', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 1, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:40:01.307Z', NULL, NULL, 'manual', NULL)
