VALUES ('38e5536b-98f5-47aa-9f21-0cee9327b880', 'SONODAY Radio', 'sonoday-radio', 'Podcast radio: curated, continuous, and always on.', 'SONODAY Radio brings back the magic of FM radio, but for podcasts. Instead of scrolling through endless feeds, choose a category (True Crime, Tech, Comedy, etc) and let it play. Curated shows stream continuously, 24/7, with real-time schedules so everyone hears the same episode at the same time. No algorithm. Just great podcasts playing like a radio station you never have to program. Rediscover a favorite or find something new! Free to listen. Premium unlocks skip, seek and custom stations.', 'https://ph-files.imgix.net/235d13f7-9ace-40ed-958c-7cb7e373dd7b.png?auto=format', 'https://www.producthunt.com/r/TSKJCAS7CRM2WB?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/TSKJCAS7CRM2WB?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'productivity', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 15, 1, 7, '2026-05-12T00:00:00.000Z', '2026-05-12T01:40:01.322Z', NULL, NULL, 'manual', NULL)
