VALUES ('af59767c-96d6-4611-af01-ddaa5905c5a0', 'DearVoice', 'dearvoice', 'Helping families preserve memories for generations.', 'DearVoice helps families preserve the voices, stories, and memories of loved ones for future generations. Unlike traditional photo albums or storage apps, DearVoice creates an interactive voice-first memory experience. Users can record life stories, advice, and family history through guided prompts or custom recordings, creating a lasting digital legacy that children and grandchildren can revisit anytime.', 'https://ph-files.imgix.net/2f66778e-d542-4817-8335-055a5805a0de.png?auto=format', 'https://www.producthunt.com/r/SP5ZZZU5XNIL2P?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/SP5ZZZU5XNIL2P?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'writing', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 1, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:40:01.329Z', NULL, NULL, 'manual', NULL)
