VALUES ('d8f437bf-4035-417e-bd47-94a6015bbe08', 'Spreaker Create | Free Podcast Editor', 'spreaker-create-free-podcast-editor', 'Record, trim, adjust and export. Free, no login, no catch.', 'Tired of paying $20/month for some basic audio editing? Spreaker Create is free, no installation and works directly in your browser. Record your voice, upload audio, layer background music, cut and move clips, adjust volume, and export a clean file. No downloads. No account. No paywall surprise. Your audio never leaves your device. 🎤 Record ⬆️ Upload ✂️ Cut & Adjust 🔊 Volume 🎵 Background music ⏪ Undo/redo 🔍 Zoom 💾 Export', 'https://ph-files.imgix.net/53156077-2fea-48ba-a27a-acfe40bd8469.png?auto=format', 'https://www.producthunt.com/r/TLYVL4M2ZIGS6P?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/TLYVL4M2ZIGS6P?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'design', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 18, 1, 9, '2026-05-12T00:00:00.000Z', '2026-05-12T01:40:01.347Z', NULL, NULL, 'manual', NULL)
