VALUES ('a616da5e-7397-40dc-b802-4ac7acf5335d', 'GetClearVoice', 'getclearvoice', 'Free AI Audio Suite: Clean, Split, Cut & Join in seconds.', 'GetClearVoice is an all-in-one professional AI audio toolkit for creators. Powered by top-tier models like Demucs and DeepFilterNet, you can remove background noise, isolate vocals or instruments, cut clips with visual waveforms, and join tracks with smooth crossfades. ✅ 100% Free & No registration required. ✅ Lightning-fast (AMD EPYC powered). ✅ Privacy-first: all files are automatically deleted. ✅ Export to MP3, WAV, or FLAC. Perfect for podcasters, musicians, and video editors.', 'https://ph-files.imgix.net/641b3873-bf88-4e8a-92f1-d078df6660bb.jpeg?auto=format', 'https://www.producthunt.com/r/K6JCBZGNFUZAV7?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/K6JCBZGNFUZAV7?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'writing', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 2, 0, 1, '2026-05-12T00:00:00.000Z', '2026-05-12T01:40:01.355Z', NULL, NULL, 'manual', NULL)
