VALUES ('e05b21a3-0b18-4378-9fd5-15d705c766b9', 'ConvertFlow - Video Converter', 'convertflow-video-converter', 'Free online tool to convert video and audio files.', 'Convert your media files in seconds. This free online tool lets you quickly change videos and audio into different formats with no hassle, no software, and no limits.', 'https://ph-files.imgix.net/d32dc39c-05b6-4151-aeba-4dfbb15b5499.png?auto=format', 'https://www.producthunt.com/r/V4Y7352JHFL2PN?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/V4Y7352JHFL2PN?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'audio', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 1, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:40:01.370Z', NULL, NULL, 'manual', NULL)
