VALUES ('f888d978-fd24-4665-8276-4c88b151b991', 'FavURL', 'favurl', 'The URL shortener with a social feed & analytics', 'FavURL is more than a URL shortener — it''s a social platform for links. Shorten any URL, share it on a public feed, and track every click with geo, device, browser, and referrer analytics. Follow people, like and repost links, organize them into collections, and discover what''s trending. Pro unlocks custom slugs, custom domains, password protection, scheduling, geo & device-based redirects. Free forever for core features. No credit card needed. → fav-url.com', 'https://ph-files.imgix.net/3a3d13c1-d2b6-407e-b895-193d65241a87.png?auto=format', 'https://www.producthunt.com/r/E3NZ6QLPKWJEDO?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/E3NZ6QLPKWJEDO?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'analytics', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'free', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:40:03.986Z', NULL, NULL, 'manual', NULL)
