VALUES ('cd7811e3-eaf4-4689-8c66-537affe9618b', 'Known Agents', 'known-agents', 'Track the bots and AI agents crawling your website', 'Known Agents is "Google Analytics for bots". AI agents, crawlers, and scrapers are now half of your website''s traffic, and they''re becoming more important to your business every day. They''re silently buying your products, reading your docs, and researching your company. Known Agents gives you realtime visibility into all of this activity. You can see which bots are visiting your site, the pages they’re most interested in, where they’re coming from, and which humans they''re referring to you.', 'https://ph-files.imgix.net/9100105d-01e3-481c-ae15-5863c510bc3b.png?auto=format', 'https://www.producthunt.com/r/K56IE2TRUY7CJD?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/K56IE2TRUY7CJD?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'analytics', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 8, FALSE, FALSE, TRUE, FALSE, 'active', 83, 8, 41, '2026-05-12T00:00:00.000Z', '2026-05-12T01:40:04.003Z', NULL, NULL, 'manual', NULL)
