VALUES ('daeefe2d-dd0e-45f4-a6d7-93d8ebdc1028', 'Bruin', 'bruin', 'The AI data agent that collaborates with your team', 'The AI Data Agent that lives, breathes, and collaborates with your team. A data analyst agent that integrates into your Slack, Teams, etc. and built on top a strong context & semantic layer using Bruin''s very own open-source tools or from your existing dbt, LookML, etc. Make your agent live inside every conversation, collaborate across teams, deep dive into the data, find insights, and turn them into actionable tasks.', 'https://ph-files.imgix.net/3e213dc9-0e60-4434-9f66-9e49576067a9.png?auto=format', 'https://www.producthunt.com/r/QTY5QSL3MRBH4I?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/QTY5QSL3MRBH4I?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'analytics', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'free', ARRAY[]::text[], TRUE, TRUE, '6.50', 6, FALSE, FALSE, TRUE, FALSE, 'active', 65, 6, 32, '2026-05-12T00:00:00.000Z', '2026-05-12T01:40:04.011Z', NULL, NULL, 'manual', NULL)
