VALUES ('62dd752f-0366-4efd-928e-41a325bb2d23', 'LeadFnF Analytics, Session Replay & Flow', 'leadfnf-analytics-session-replay-flow', 'Web analytics with session recordings, heatmaps & AI insight', 'LeadFnF is a web analytics platform that combines pageview tracking, session recordings, click heatmaps, funnels, and AI-powered insights, all from a single lightweight script. Unlike GA4, there''s no complex setup or sampled data. Unlike Plausible, you get session replays and heatmaps built in. One tool replaces three: analytics, recordings, and heatmaps at a fraction of the cost. Built for founders and small teams who want real answers, not dashboards to manage.', 'https://ph-files.imgix.net/f514645a-a761-4a4f-819f-373ad1f49ba1.png?auto=format', 'https://www.producthunt.com/r/VKAXOJHJH7UPQZ?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/VKAXOJHJH7UPQZ?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'analytics', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:40:04.019Z', NULL, NULL, 'manual', NULL)
