VALUES ('2f4e74f7-a6ab-41f6-894a-b9e12357e58f', 'Football Predictor', 'football-predictor', 'AI football predictions with odds and accuracy tracking', 'Football Predictor is an AI-powered football analysis platform that combines match data, odds context, team form, injuries, and historical performance to generate transparent match predictions. It covers major leagues including the Premier League, La Liga, Bundesliga, Serie A, Ligue 1, Champions League, CSL, and World Cup, with public accuracy tracking for every prediction model.', 'https://ph-files.imgix.net/6201ebd5-9080-4498-8715-649ae806615c.png?auto=format', 'https://www.producthunt.com/r/7R6XRNOAMLRWK7?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/7R6XRNOAMLRWK7?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'analytics', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:40:04.026Z', NULL, NULL, 'manual', NULL)
