VALUES ('6ee36bdf-6ea6-4e55-a2c9-10a01f2253c6', 'Footy Analyser', 'footy-analyser', 'Pro level performance analysis on your recorded matches', 'Free football performance analytics from your Strava activities to help you gauge how your physical performance is changing over time. Currently, the only way to get this level of analysis across the history of your match data, is to pay for a certain GPS and use a certain app. This makes analysis accesible to anyone with a smart watch and a free Strava account.', 'https://ph-files.imgix.net/9841859a-c8ca-41d6-a97f-c26ca74301dc.png?auto=format', 'https://www.producthunt.com/r/WMUGC2XO4F2STC?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/WMUGC2XO4F2STC?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'analytics', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:40:04.033Z', NULL, NULL, 'manual', NULL)
