VALUES ('2be8ed9e-57d8-417e-b7cd-2068f7cba456', 'JobTrends.ai', 'jobtrends-ai', 'Real-time analytics for the US tech job market', 'Real-time US tech job market analytics powered by data from thousands of job postings daily. JobTrends.ai analyzes 5,000+ new tech job postings every day to track hiring trends across software engineering, data, cloud, DevOps, AI, cybersecurity, and more. Explore skills demand, salary benchmarks, remote vs onsite trends, top hiring companies, and career insights through interactive analytics and filters instead of endlessly scrolling job boards.', 'https://ph-files.imgix.net/1f663961-7c6b-49e0-916b-d2dcc301c1c9.png?auto=format', 'https://www.producthunt.com/r/YPGDII4VTS2ZSV?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/YPGDII4VTS2ZSV?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'analytics', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 3, 0, 1, '2026-05-12T00:00:00.000Z', '2026-05-12T01:40:04.040Z', NULL, NULL, 'manual', NULL)
