VALUES ('884a9997-cb0d-4815-b61e-267d3afd04f3', 'Workrate', 'workrate', 'Real-time performance engine for data-driven teams.', 'Workrate is the ultimate all-in-one workspace for high-performing teams. It combines robust project management and task tracking with real-time performance analytics and instant communication. From built-in video meetings and team chat to automated productivity scoring and performance trend charts, Workrate eliminates tool sprawl. Whether you''re managing remote team members or office-based projects, it provides the transparency and tools needed to maintain a consistent, top-tier work rate.', 'https://ph-files.imgix.net/31ea6b3f-c8a9-41c7-9a43-b4bb2a363667.png?auto=format', 'https://www.producthunt.com/r/KRPEZI6RZWPLAR?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/KRPEZI6RZWPLAR?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'productivity', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:40:04.054Z', NULL, NULL, 'manual', NULL)
