VALUES ('f5bc175a-9fda-4d5b-9a74-543809a7040f', 'Tempo - Your Life Analytics', 'tempo-your-life-analytics', 'Discover your daily habits', 'Tempo automatically tracks where your time goes without manual logging. Using on-device algorithms, it detects places (home, work, restaurants...), transport modes (walking, cycling, metro, tram…), and generates insights about your routines, mobility, and carbon footprint. The app even identifies metro and tram lines and stations (currently available in London and major French cities). All location processing stays entirely on your iPhone for maximum privacy.', 'https://ph-files.imgix.net/682e169d-2f34-4279-b639-3fa5b1a82be8.png?auto=format', 'https://www.producthunt.com/r/NO6U5Y7YXRPUMA?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/NO6U5Y7YXRPUMA?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'productivity', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 1, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:40:04.068Z', NULL, NULL, 'manual', NULL)
