VALUES ('74989794-215f-4e38-8ad5-0f8cd67ede5b', 'Kulma.co', 'kulma-co', 'Skip the GA4 dashboard. Get the weekly brief instead. ', 'Most GA4 tools give you another dashboard to log into. Kulma sends you a short brief every Monday morning instead, written like a memo from an analyst who actually looked at your data. It tells you what changed last week, what it probably means, and what to look at next. No charts to decipher, no template to build, no app to remember.', 'https://ph-files.imgix.net/fae53295-64f6-4746-9ab2-0eb49dd264b6.png?auto=format', 'https://www.producthunt.com/r/CKSEIGAIJ7KXOV?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/CKSEIGAIJ7KXOV?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'productivity', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:40:04.075Z', NULL, NULL, 'manual', NULL)
