VALUES ('eb24e5e2-c33f-48a2-a368-9d052d17b5b6', 'Advancelytics', 'advancelytics', 'Understand buyer decisions on your website in real time', 'Advancelytics helps SaaS companies understand how buyers make decisions on their websites. Traditional analytics tools track traffic and conversions but rarely explain why visitors hesitate before converting. Advancelytics detects behavioral signals like pricing comparisons, repeated feature exploration, and evaluation delays, helping businesses engage visitors at the right moment and reduce lost conversions.', 'https://ph-files.imgix.net/9bb1806c-d51e-4345-bd50-04dedc78c178.x-icon?auto=format', 'https://www.producthunt.com/r/ORPRNJWSRWTXZH?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/ORPRNJWSRWTXZH?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'analytics', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 0, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:40:04.084Z', NULL, NULL, 'manual', NULL)
