VALUES ('96125742-1114-41b4-ba35-7c305d5fbd48', 'WealthLens', 'wealthlens', 'WealthLens: Your Wealth, Under Your Lens', 'WealthLens disrupts fintech by prioritizing Financial Sovereignty. Unlike competitors who mine your data, our Zero-Knowledge Vault uses client-side encryption—you hold the keys, we just store the shards. Our Institutional Rule Engine gives you surgical control over transaction mapping, while FIRE-Native Analytics project your path to retirement in real-time. It’s not a budget app; it’s an institutional treasury for the sovereign investor.', 'https://ph-files.imgix.net/7cba913b-a53a-4262-a17b-6779200a8bad.png?auto=format', 'https://www.producthunt.com/r/4XKCSKT66ZSPAK?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/4XKCSKT66ZSPAK?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'analytics', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 1, 0, 0, '2026-05-12T00:00:00.000Z', '2026-05-12T01:40:04.151Z', NULL, NULL, 'manual', NULL)
