VALUES ('5b5e1f64-3d66-48c7-9203-3fc2a37d8ad9', 'EcoSEO', 'ecoseo', 'Descrições de Produto que Vendem e Posicionam', 'Gere automaticamente títulos SEO, descrições persuasivas e meta-descriptions otimizadas para os seus produtos. EcoSEO é a plataforma que gera automaticamente: ✅ Títulos SEO otimizados ✅ Descrições persuasivas que convertem ✅ Meta-descriptions que atraem cliques Tudo em segundos, com IA. Sem cartão de crédito. 5 gerações gratuitas por mes.', 'https://ph-files.imgix.net/dc2bf80a-75a1-49c1-a4b6-9361ee986b99.png?auto=format', 'https://www.producthunt.com/r/DO7GM4GGSSSLZM?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'https://www.producthunt.com/r/DO7GM4GGSSSLZM?utm_campaign=producthunt-api&utm_medium=api-v2&utm_source=Application%3A+Novex+Hunt+ai+%28ID%3A+278703%29', 'productivity', ARRAY['new','product-hunt','free','africa-friendly']::text[], 'freemium', ARRAY[]::text[], TRUE, TRUE, '6.50', 1, FALSE, FALSE, TRUE, FALSE, 'active', 3, 0, 1, '2026-05-12T00:00:00.000Z', '2026-05-12T01:40:04.199Z', NULL, NULL, 'manual', NULL)
